export interface Drama {
  title: string;
  author: string;
  category: string;
  summary?: string;
  year?: string;
  facts?: string;
}

export const dramas: Drama[] = [

  // British Plays
  { title: "Ralph Roister Doister", author: "Nicholas Udall", category: "British", year: "c. 1552", summary: "A boastful and foolish soldier, Ralph Roister Doister, pursues the widow Dame Christian Custance, who is already betrothed. His clumsy wooing, aided by the rogue Matthew Merrygreek, ends in comic failure. It is considered the first regular comedy in English literature." },
  { title: "Gorboduc", author: "Thomas Norton and Thomas Sackville", category: "British", year: "1561", summary: "The legendary British king Gorboduc divides his kingdom between his two sons, Ferrex and Porrex, leading to fratricidal conflict and civil war. The play is a political tragedy warning against divided rule and the dangers of an unsettled succession. It is the first blank verse tragedy in English." },
  { title: "Gammer Gurton's Needle", author: "Anonymous", category: "British", year: "c. 1553", summary: "A village farce in which Gammer Gurton loses her sewing needle and the entire community is thrown into comic uproar searching for it. A mischievous rogue named Diccon stirs up quarrels among the neighbours. The needle is found in a farcical conclusion." },
  { title: "The Four P's", author: "John Heywood", category: "British", year: "c. 1544", summary: "Four characters — a Palmer, a Pardoner, a Pothecary, and a Pedlar — hold a contest to see who can tell the greatest lie. The Palmer wins by claiming he has never seen a woman out of patience. The play is a satirical interlude mocking religious hypocrisy and superstition." },
  { title: "The Play of the Weather", author: "John Heywood", category: "British", year: "1533", summary: "Jupiter holds a parliament in which various characters petition for their preferred type of weather. The debate satirises human selfishness and the impossibility of pleasing everyone. Jupiter ultimately decides to keep the weather as it is." },

  { title: "Doctor Faustus", author: "Christopher Marlowe", category: "British", year: "c. 1592", summary: "The scholar Faustus sells his soul to the devil Mephistopheles in exchange for twenty-four years of power and knowledge. Despite moments of doubt, he squanders his powers on trivial tricks and is finally dragged to hell. The play explores the Renaissance tension between ambition and damnation.", facts: "Based on the German legend of Faust; contains some of the most famous lines in English drama, including 'Was this the face that launched a thousand ships?'" },
  { title: "Tamburlaine the Great", author: "Christopher Marlowe", category: "British", year: "c. 1587", summary: "A Scythian shepherd, Tamburlaine, rises through ruthless military conquest to become ruler of a vast empire. The two-part play charts his campaigns across Asia and his consuming desire for absolute power. His death in Part II suggests that even the mightiest conqueror cannot escape mortality." },
  { title: "The Jew of Malta", author: "Christopher Marlowe", category: "British", year: "c. 1589", summary: "The wealthy Jew Barabas is dispossessed of his fortune by the Governor of Malta and plots an elaborate and bloody revenge. His machinations lead to mass poisonings, betrayals, and his own spectacular death. The play is a dark comedy exploring greed, hypocrisy, and religious conflict." },
  { title: "Edward II", author: "Christopher Marlowe", category: "British", year: "c. 1592", summary: "King Edward II's favouritism toward his male favourite Gaveston alienates the English nobility and his queen, Isabella, leading to rebellion and civil war. Edward is eventually deposed and murdered in prison. The play is a tragedy of political weakness and personal obsession." },

  { title: "The Spanish Tragedy", author: "Thomas Kyd", category: "British", year: "c. 1587", summary: "Hieronimo, Marshal of Spain, seeks revenge for the murder of his son Horatio by the Spanish and Portuguese nobility. When justice is denied, he stages a play within a play in which the killings are carried out in earnest. It is one of the earliest and most influential revenge tragedies in English drama." },

  { title: "Hamlet", author: "William Shakespeare", category: "British", year: "c. 1600", summary: "Prince Hamlet of Denmark is visited by his father's ghost, who reveals he was murdered by Hamlet's uncle Claudius, now king and married to Hamlet's mother. Hamlet's brooding quest for revenge leads to a chain of deaths, including his own. The play is a profound meditation on mortality, justice, and inaction.", facts: "Shakespeare's longest play; the role of Hamlet is considered one of the greatest challenges for any actor." },
  { title: "Othello", author: "William Shakespeare", category: "British", year: "c. 1603", summary: "The Moorish general Othello is manipulated by his envious ensign Iago into believing his faithful wife Desdemona has been unfaithful. Consumed by jealousy, Othello murders Desdemona and, upon learning the truth, kills himself. The play is a tragedy of racial prejudice, jealousy, and manipulation.", facts: "One of the few Shakespearean plays to feature a Black protagonist; Verdi's opera 'Otello' is based on this play." },
  { title: "Macbeth", author: "William Shakespeare", category: "British", year: "c. 1606", summary: "Spurred by a prophecy from three witches and urged on by his wife, the Scottish general Macbeth murders King Duncan and seizes the throne. His reign descends into tyranny, paranoia, and further murders, leading to his downfall and death. The play examines the corrupting nature of unchecked ambition and guilt.", facts: "Often referred to by actors as 'The Scottish Play' due to a long-standing superstition that saying its name inside a theatre brings bad luck." },
  { title: "King Lear", author: "William Shakespeare", category: "British", year: "c. 1605", summary: "The aging King Lear divides his kingdom among his daughters based on flattery, disowning the only one who truly loves him, Cordelia. Betrayed and cast out by his two elder daughters, Lear descends into madness on the stormy heath. The play is a devastating tragedy of pride, filial ingratitude, and redemption.", facts: "For over 150 years (1681–1838), Nahum Tate's happy-ending version of the play was performed instead of Shakespeare's original tragedy." },
  { title: "Much Ado About Nothing", author: "William Shakespeare", category: "British", year: "c. 1598", summary: "Set in Messina, the play follows two pairs of lovers: the sparring Beatrice and Benedick, and the more conventional Hero and Claudio. A villain's deception leads Claudio to falsely accuse Hero of infidelity, nearly destroying their union. The play balances witty comedy with darker themes of honour and deception." },
  { title: "As You Like It", author: "William Shakespeare", category: "British", year: "c. 1599", summary: "Rosalind, banished by her usurping uncle, flees to the Forest of Arden disguised as a boy, accompanied by her cousin Celia. There she encounters Orlando, whom she loves, and playfully tests his devotion while multiple love plots unfold. The play is a pastoral comedy celebrating love, wit, and the contrast between court and nature." },
  { title: "Richard II", author: "William Shakespeare", category: "British", year: "c. 1595", summary: "King Richard II's weak and arbitrary rule provokes the rebellion of Henry Bolingbroke, who deposes him and takes the throne as Henry IV. Richard is imprisoned and eventually murdered, mourning the loss of his identity as king. The play meditates on the nature of kingship, legitimacy, and the tragedy of self-knowledge too late." },
  { title: "Julius Caesar", author: "William Shakespeare", category: "British", year: "1599", summary: "A group of Roman senators led by Brutus assassinate Julius Caesar, fearing he will become a tyrant. Mark Antony's funeral oration turns the Roman populace against the conspirators, igniting civil war. The play explores themes of honour, political manipulation, and the consequences of idealism." },
  { title: "Romeo and Juliet", author: "William Shakespeare", category: "British", year: "c. 1594", summary: "Two young lovers from feuding families in Verona, Romeo Montague and Juliet Capulet, meet secretly and marry. A series of tragic misunderstandings leads to both their deaths in the Capulet tomb. The play is an enduring tragedy of young love destroyed by family hatred and fate." },
  { title: "Titus Andronicus", author: "William Shakespeare", category: "British", year: "c. 1593", summary: "The Roman general Titus Andronicus sacrifices the son of the captured Goth queen Tamora, igniting a cycle of brutal revenge. Tamora and her lover Aaron engineer the rape and mutilation of Titus's daughter Lavinia and the deaths of his sons. The play culminates in a gruesome revenge banquet and multiple murders." },
  { title: "Love's Labour's Lost", author: "William Shakespeare", category: "British", year: "c. 1594", summary: "The King of Navarre and his lords vow to devote themselves to study for three years, forswearing women. Their resolve immediately collapses when the Princess of France and her ladies arrive on a diplomatic mission. The play is a witty comedy about the futility of denying love and the gap between ideals and reality." },
  { title: "A Midsummer Night's Dream", author: "William Shakespeare", category: "British", year: "c. 1595", summary: "Four young Athenian lovers flee into an enchanted forest where the fairy king Oberon and his mischievous servant Puck meddle with their affections through a love potion. A troupe of amateur actors also rehearse in the forest, and their clownish performance provides a comic play-within-a-play. The result is a magical comedy about the irrationality of love and the power of imagination.", facts: "The play's wedding theme has made it a popular choice for outdoor summer performances." },
  { title: "All's Well That Ends Well", author: "William Shakespeare", category: "British", year: "c. 1604", summary: "The physician's daughter Helena loves the nobleman Bertram, who is forced to marry her but immediately abandons her for the wars. Through wit and determination, Helena fulfils the impossible conditions Bertram sets for reconciliation. The play is a problem comedy exploring virtue, class, and the nature of honour." },
  { title: "The Two Gentlemen of Verona", author: "William Shakespeare", category: "British", year: "c. 1589", summary: "Two friends, Valentine and Proteus, both end up pursuing the same woman, Silvia, in Milan after Proteus betrays his beloved Julia and his friend. Julia follows Proteus in disguise, and the play ends with rapid reconciliations. It is considered one of Shakespeare's earliest comedies, exploring friendship, betrayal, and love." },
  { title: "Measure for Measure", author: "William Shakespeare", category: "British", year: "c. 1603", summary: "The Duke of Vienna hands authority to the puritanical Angelo while he secretly observes the city in disguise. Angelo condemns Claudio to death for fornication, then hypocritically proposes to spare him only if his sister Isabella submits sexually to him. The play is a dark problem comedy exploring justice, mercy, hypocrisy, and the abuse of power." },
  { title: "The Merchant of Venice", author: "William Shakespeare", category: "British", year: "c. 1596", summary: "The merchant Antonio borrows money from the Jewish moneylender Shylock to help his friend Bassanio woo the heiress Portia, pledging a pound of his own flesh as bond. When Antonio's ships are lost, Shylock demands his bond, but Portia disguised as a lawyer defeats him in court. The play raises enduring questions about mercy, justice, and religious prejudice." },
  { title: "Twelfth Night", author: "William Shakespeare", category: "British", year: "c. 1601", summary: "Viola, shipwrecked in Illyria, disguises herself as a boy and serves Duke Orsino, with whom she falls in love, while he pursues the Lady Olivia. Olivia instead falls for Viola in disguise, creating a comic love triangle resolved by the arrival of Viola's twin brother Sebastian. The play is a festive comedy about love, gender, and mistaken identity." },
  { title: "Antony and Cleopatra", author: "William Shakespeare", category: "British", year: "c. 1606", summary: "The Roman general Mark Antony is torn between his duty to Rome and his passionate love for the Egyptian queen Cleopatra. His political and military failures lead to his suicide, followed by Cleopatra's own death to avoid Roman captivity. The play is a sweeping tragedy contrasting Roman duty and Egyptian sensuality." },
  { title: "The Tempest", author: "William Shakespeare", category: "British", year: "c. 1610", summary: "The sorcerer Prospero, exiled on a remote island, uses his magical powers and the spirit Ariel to orchestrate the arrival of his enemies by shipwreck. Through illusion and enchantment he engineers reconciliation, justice, and the marriage of his daughter Miranda. The play is widely read as Shakespeare's farewell to the stage, exploring art, power, and forgiveness." },
  { title: "The Comedy of Errors", author: "William Shakespeare", category: "British", year: "c. 1594", summary: "Two sets of identical twins — the Antipholus brothers and their servants the Dromio brothers — are separated at birth and unknowingly reunite in the city of Ephesus, causing a cascade of comic mistaken identities. The confusion involves accusations of madness, infidelity, and theft before the truth is revealed. It is Shakespeare's shortest and most farcical play." },

  { title: "Every Man in His Humour", author: "Ben Jonson", category: "British", year: "1598", summary: "Set in London, the play follows the gulling of various characters whose personalities are dominated by a single obsessive 'humour' or trait, including the jealous merchant Kitely and the braggart soldier Bobadill. The young gallant Edward Knowell navigates these comic follies with wit. The play established the comedy of humours as a major Jacobean genre.", facts: "William Shakespeare is known to have acted in the original production of this play." },
  { title: "Every Man Out of His Humour", author: "Ben Jonson", category: "British", year: "1599", summary: "A satirical comedy in which various characters, each ruled by an absurd humour or affectation, are exposed and cured of their folly. The play includes meta-theatrical commentary through the characters of Cordatus and Mitis who discuss the action. It is a more ambitious and darker sequel to Jonson's earlier comedy." },
  { title: "The Alchemist", author: "Ben Jonson", category: "British", year: "1610", summary: "Three London con artists — Subtle, Face, and Doll Common — set up an alchemical fraud in their master's vacated house, gulling a succession of greedy and gullible victims. Each victim believes they will receive the philosopher's stone, instant wealth, or magical powers. The play is a brilliantly plotted satire on human greed and credulity.", facts: "Samuel Taylor Coleridge considered this play to have one of the three most perfect plots in literature." },
  { title: "Volpone", author: "Ben Jonson", category: "British", year: "1606", summary: "The Venetian magnifico Volpone, aided by his servant Mosca, pretends to be dying in order to extract gifts from legacy hunters who each hope to be named his heir. The scheme spirals out of control through Volpone's own greed and Mosca's treachery. The play is a savage satirical comedy about avarice, deception, and justice.", facts: "The characters' names are Italian for animals: Volpone (Fox), Mosca (Fly), Voltore (Vulture), Corbaccio (Raven), and Corvino (Crow)." },
  { title: "Epicoene, or The Silent Woman", author: "Ben Jonson", category: "British", year: "1609", summary: "Morose, a man who cannot bear noise, is tricked by his nephew into marrying Epicoene, supposedly a silent woman, who turns out to be anything but. The marriage is complicated by a crowd of noisy visitors and social pretenders. The play ends with a shocking revelation about Epicoene's true identity." },

  { title: "The Knight of the Burning Pestle", author: "Francis Beaumont", category: "British", year: "c. 1607", summary: "A grocer and his wife in the audience interrupt a play being performed and insist that their apprentice Rafe be given a starring role as a chivalric hero. The result is a chaotic and affectionate parody of citizen comedy and popular romance. The play is a pioneering meta-theatrical work mocking theatrical conventions and audience taste." },
  { title: "The Maid's Tragedy", author: "Beaumont and Fletcher", category: "British", year: "c. 1610", summary: "Amintor is forced by the King to abandon his betrothed Aspatia and marry Evadne, who is the King's secret mistress. When Evadne reveals the truth on their wedding night, Amintor is trapped between honour and duty. The resulting tragedy involves assassination, revenge, and multiple deaths." },

  { title: "The Changeling", author: "Thomas Middleton", category: "British", year: "1622", summary: "Beatrice-Joanna hires the repulsive servant De Flores to murder the man she is betrothed to so she may marry another, but De Flores demands sexual possession as his price. Bound by mutual guilt, the two enter a dark, compulsive relationship that destroys them both. The play is a psychological tragedy exploring moral corruption and the nature of evil." },
  { title: "A Game at Chess", author: "Thomas Middleton", category: "British", year: "1624", summary: "An allegorical play representing the political conflict between England and Spain as a chess game, with pieces representing real contemporary figures including King James I and the Spanish ambassador. The White pieces (England/Protestantism) defeat the Black pieces (Spain/Catholicism). It was a sensational topical satire that ran for nine consecutive days before being banned." },
  { title: "Women Beware Women", author: "Thomas Middleton", category: "British", year: "c. 1621", summary: "The play follows two plots: the seduction of the merchant's wife Bianca by the Duke of Florence, and the incestuous passion of Hippolito for his niece Isabella. Both plots converge in a spectacular and deadly masque in the final act. The play is a dark tragedy about sexual corruption, complicity, and the commodification of women." },

  { title: "The White Devil", author: "John Webster", category: "British", year: "1612", summary: "The Venetian nobleman Brachiano murders his wife with the help of his lover Vittoria Corombona and her brother Flamineo. Vittoria is tried for adultery in a brilliant courtroom scene before the lovers are ultimately killed in revenge. The play is a lurid Jacobean tragedy exposing the moral corruption beneath aristocratic surfaces." },
  { title: "The Duchess of Malfi", author: "John Webster", category: "British", year: "c. 1612", summary: "The widowed Duchess of Malfi secretly marries her steward Antonio against the wishes of her tyrannical brothers Ferdinand and the Cardinal. Her brothers hire a spy, Bosola, to watch her, and when her secret marriage is discovered they subject her to prolonged psychological torment and finally murder her. The play is a masterpiece of Jacobean tragedy, exploring power, gender, and mortality.", facts: "The play is based on the real-life Giovanna d'Aragona, Duchess of Amalfi, who died in 1510." },

  { title: "'Tis Pity She's a Whore", author: "John Ford", category: "British", year: "c. 1629", summary: "Giovanni and his sister Annabella engage in a passionate incestuous love affair in Parma, with full knowledge of its sinfulness. When Annabella is married off and becomes pregnant by Giovanni, the affair ends in horrific violence. The play is a Caroline tragedy that provocatively explores forbidden desire and moral transgression." },

  { title: "The Shoemaker's Holiday", author: "Thomas Dekker", category: "British", year: "1599", summary: "The jovial master shoemaker Simon Eyre rises to become Lord Mayor of London while his journeyman Rafe returns from the wars to reclaim his wife. A romantic subplot involves the aristocrat Rowland Lacy disguising himself as a Dutch shoemaker to be near his beloved Rose. The play is a festive city comedy celebrating artisan pride and social mobility." },

  { title: "Samson Agonistes", author: "John Milton", category: "British", year: "1671", summary: "The blinded and captive Samson, held by the Philistines, receives a series of visitors including his father Manoa and his betrayer Dalila as he struggles with despair and renews his faith in God. His story culminates in his pulling down the Philistine temple, killing himself and his enemies. The play is a closet drama modelled on Greek tragedy, exploring heroic suffering, faith, and spiritual regeneration." },

  { title: "All for Love", author: "John Dryden", category: "British", year: "1677", summary: "Dryden's neoclassical retelling of the story of Antony and Cleopatra focuses on the final hours before their suicides, as Antony is torn between his love for Cleopatra and his duty to Rome and his wife Octavia. The play observes the unities of time, place, and action, unlike Shakespeare's version. It is considered Dryden's finest achievement in heroic tragedy." },
  { title: "The Conquest of Granada", author: "John Dryden", category: "British", year: "1670", summary: "The heroic warrior Almanzor fights for various factions during the Spanish conquest of Moorish Granada while pursuing his love for Almahide. The two-part play is filled with extravagant rhetoric, grand passions, and martial spectacle typical of Restoration heroic drama. It both celebrated and gently satirised the conventions of the heroic play." },

  { title: "The Country Wife", author: "William Wycherley", category: "British", year: "1675", summary: "The rake Horner spreads the rumour that he is impotent after an illness in order to gain free access to the wives of jealous husbands. The naive Mr Pinchwife brings his innocent country wife Margery to London, where she becomes one of Horner's conquests. The play is a brilliantly cynical Restoration comedy of manners satirising marriage, jealousy, and sexual hypocrisy." },
  { title: "Love in a Wood", author: "William Wycherley", category: "British", year: "1671", summary: "Set among the romantic intrigues and assignations in St James's Park, the play follows multiple couples navigating jealousy, deception, and social climbing in Restoration London. The park serves as a space where class boundaries blur and sexual freedoms are pursued. It was Wycherley's debut and established his reputation as a sharp social satirist." },
  { title: "The Plain Dealer", author: "William Wycherley", category: "British", year: "1676", summary: "The misanthropic sea captain Manly returns from battle to find his beloved Olivia has married another man and stolen his fortune. Disillusioned with a corrupt society, he is ultimately saved by the loyal Fidelia, who has followed him in disguise. The play is Wycherley's harshest satirical comedy, heavily influenced by Molière's Le Misanthrope." },

  { title: "The Relapse", author: "John Vanbrugh", category: "British", year: "1696", summary: "Loveless, recently reformed, is tempted back into infidelity when he returns to London and meets the alluring Berinthia. A parallel plot follows the foolish Sir Novelty Fashion (Lord Foppington) and his brother Young Fashion, who steals Foppington's wealthy bride by impersonating him. The play is a witty Restoration comedy questioning the durability of moral reform." },
  { title: "The Provoked Wife", author: "John Vanbrugh", category: "British", year: "1697", summary: "Lady Brute, married to the boorish and drunken Sir John Brute, is tempted to take a lover, Constant, who sincerely courts her. Meanwhile her niece Bellinda is also pursued by Constant's friend Heartfree. The play candidly examines the misery of an unhappy marriage and the limited options available to women." },

  { title: "The Man of Mode", author: "George Etherege", category: "British", year: "1676", summary: "The brilliant and heartless rake Dorimant juggles his mistresses, discards one, pursues a rich heiress named Harriet, and torments the foolish Sir Fopling Flutter. Harriet matches Dorimant in wit and refuses to be easily won. The play defines the Restoration comedy of manners and created the archetypal Restoration hero and fop." },
  { title: "The Comical Revenge", author: "George Etherege", category: "British", year: "1664", summary: "The play interweaves a heroic plot of love and honour among the nobility with a comic plot involving the drunken antics of Sir Nicholas Cully and his companions. The servant Dufoy is locked in a tub as punishment, providing farcical comedy alongside the more serious romantic intrigues. It is Etherege's first play and an important early example of Restoration comedy." },
  { title: "She Would If She Could", author: "George Etherege", category: "British", year: "1668", summary: "Two country ladies, Ariana and Gatty, come to London seeking adventure and encounter two young gallants, Courtal and Freeman, who pursue them through parks and playhouses. The witty exchanges and sexual sparring between the couples form the heart of the play. It is considered an important step in the development of the Restoration comedy of manners." },

  { title: "The Old Bachelor", author: "William Congreve", category: "British", year: "1693", summary: "The confirmed bachelor Heartwell is unexpectedly trapped into a fake marriage with the scheming Silvia while other romantic intrigues unfold among the play's many couples. The witty Bellmour and Vainlove manoeuvre through London's social and sexual world with brilliant repartee. It was Congreve's highly successful debut, praised by Dryden." },
  { title: "The Double Dealer", author: "William Congreve", category: "British", year: "1693", summary: "The villain Maskwell poses as the devoted friend of Mellefont while secretly plotting to steal his bride Cynthia and his uncle's fortune. His elaborate double-dealing is eventually exposed. The play is a darker Restoration comedy exploring treachery, hypocrisy, and the corruption of friendship." },
  { title: "Love for Love", author: "William Congreve", category: "British", year: "1695", summary: "The spendthrift Valentine Legend feigns madness to avoid signing over his inheritance to his brother while pursuing the heiress Angelica. Angelica tests his sincerity before finally declaring her love. The play is a lively comedy of manners blending romantic sentiment with satirical wit." },
  { title: "The Way of the World", author: "William Congreve", category: "British", year: "1700", summary: "Mirabell and Millamant wish to marry, but require the consent and fortune controlled by Lady Wishfort, whom Mirabell has previously deceived. Their famous 'proviso scene', in which they negotiate the terms of a modern marriage, is the heart of the play. It is considered the finest Restoration comedy, celebrated for its dazzling prose style and complex plot.", facts: "The play was a relative failure on its first production, leading Congreve to retire from playwriting at the age of 30." },

  { title: "The Beggar's Opera", author: "John Gay", category: "British", year: "1728", summary: "The dashing highwayman Macheath is arrested after being betrayed by the daughters of two rivals, Peachum and Lockit, both of whom claim he is their son-in-law. The play satirises Italian opera, Walpole's government, and the moral equivalence between criminals and the ruling class. Its ballad opera format was enormously influential and made Gay famous overnight.", facts: "The play was so successful it was said to have made 'Gay rich and Rich gay' (John Rich was the theatre manager)." },

  { title: "She Stoops to Conquer", author: "Oliver Goldsmith", category: "British", year: "1773", summary: "The shy young gentleman Marlow, who is bold with lower-class women but tongue-tied before ladies, is tricked into mistaking the Hardcastle family home for an inn and its daughter Kate for a barmaid. Kate exploits the confusion to draw out Marlow's true character and win his love. The play is a warm-hearted sentimental comedy championing natural feeling over fashionable affectation.", facts: "The play's title was suggested by a line from Dryden; it remains one of the most popular 18th-century plays on the modern stage." },

  { title: "The Rivals", author: "Richard Brinsley Sheridan", category: "British", year: "1775", summary: "Captain Absolute is in love with Lydia Languish, who desires a penniless lover, so he woos her disguised as the poor ensign Beverley. The complications multiply as rival suitors and meddlesome parents become involved. The play introduced the immortal Mrs Malaprop, whose hilarious misuse of words gave the language the term 'malapropism'.", facts: "Sheridan was only 23 when he wrote this play; it failed on its first night but became a huge hit after revisions." },
  { title: "The School for Scandal", author: "Richard Brinsley Sheridan", category: "British", year: "1777", summary: "Sir Peter Teazle's young wife is drawn into a circle of malicious gossips while his ward Lady Sneerwell plots to destroy reputations. The virtuous Joseph Surface is revealed as a hypocrite while his seemingly dissolute brother Charles proves to have a generous heart. The play is a brilliant satirical comedy of manners attacking hypocrisy, scandal, and false sentiment." },
  { title: "The Critic", author: "Richard Brinsley Sheridan", category: "British", year: "1779", summary: "The vain playwright Mr Puff invites the critics Sneer and Dangle to watch the rehearsal of his absurd tragedy about the Spanish Armada. The play is a farcical theatrical satire mocking pretentious dramatists, incompetent actors, and sentimental drama. It is widely regarded as one of the finest theatrical burlesques in English." },

  { title: "A Woman of No Importance", author: "Oscar Wilde", category: "British", year: "1893", summary: "The witty but cynical Lord Illingworth offers a secretarial position to the earnest young Gerald Arbuthnot, not knowing Gerald is his illegitimate son. Gerald's American friend Hester and his mother Rachel resist Illingworth's charm and reveal his moral emptiness. The play is a social comedy with a serious critique of double standards and the treatment of fallen women." },
  { title: "The Importance of Being Earnest", author: "Oscar Wilde", category: "British", year: "1895", summary: "Two bachelors, Algernon and Jack, each maintain fictitious alter egos to escape social obligations and pursue the women they love. Both women insist on marrying a man named Ernest, leading to comic attempts to be rechristened. The play is Wilde's masterpiece, a farcical comedy of manners satirising Victorian society through brilliant epigrams and absurd plotting.", facts: "The play's opening night was the climax of Wilde's career, but also the beginning of his downfall as the Marquess of Queensberry attempted to disrupt it." },
  { title: "An Ideal Husband", author: "Oscar Wilde", category: "British", year: "1895", summary: "The respected politician Sir Robert Chiltern is blackmailed by the scheming Mrs Cheveley over a corrupt secret from his past. His friend Lord Goring helps him navigate the crisis while the play questions whether a man's youthful mistake should define his entire life. The play is a witty comedy exploring idealism, political corruption, and the nature of forgiveness." },

  { title: "The Silver Box", author: "John Galsworthy", category: "British", year: "1906", summary: "A wealthy young man steals a purse while drunk, and a poor man is jailed for a similar theft, exposing the stark inequality of the Edwardian legal system. The play juxtaposes the fates of the rich man's son and a working-class man with deliberate naturalistic balance. It is Galsworthy's first play and a landmark of British social realism." },
  { title: "Justice", author: "John Galsworthy", category: "British", year: "1910", summary: "The young clerk William Falder forges a cheque to help a woman escape an abusive husband and is imprisoned, where the cruelty of solitary confinement breaks him. On release he struggles to rebuild his life but is crushed by a merciless system. The play was influential in campaigning for prison reform." },
  { title: "Strife", author: "John Galsworthy", category: "British", year: "1909", summary: "The intransigent chairman of a tin works, Anthony, and the equally stubborn union leader Roberts clash in a bitter industrial dispute that brings suffering to both workers and shareholders. A moderate compromise is finally agreed upon, but both leaders are repudiated by their own sides. The play is an even-handed study of industrial conflict and the human cost of ideology." },

  { title: "The Lady's Not for Burning", author: "Christopher Fry", category: "British", year: "1948", summary: "In a medieval English town, the weary soldier Thomas Mendip tries to get himself hanged for a murder he may not have committed, while the young Jennet Jourdemayne is accused of witchcraft. Their unlikely encounter draws them together as the town rushes towards an unjust execution. The play is a lyrical verse comedy celebrating life, love, and the irrational will to live.", facts: "A major hit in the post-war verse drama revival; starred Richard Burton and Claire Bloom." },
  { title: "Venus Observed", author: "Christopher Fry", category: "British", year: "1950", summary: "An ageing Duke invites three former mistresses to watch an eclipse and asks his son to choose which one he should marry.", facts: "Written for Laurence Olivier; won the Queen's Gold Medal for Poetry." },
  { title: "A Phoenix Too Frequent", author: "Christopher Fry", category: "British", year: "1946", summary: "A Roman widow decides to die in her husband's tomb but is distracted by a handsome young soldier guarding a nearby corpse.", facts: "A witty one-act comedy that established Fry's reputation for exuberant poetic language." },
  { title: "The Dark Is Light Enough", author: "Christopher Fry", category: "British", year: "1954", summary: "Set during the Hungarian Revolution of 1848, a countess provides sanctuary to a deserter despite the danger to her family.", facts: "Written for Edith Evans; explores themes of non-violence and divine grace." },

  { title: "Pygmalion", author: "George Bernard Shaw", category: "British", year: "1913", summary: "The phonetician Professor Higgins bets that he can pass off the Cockney flower girl Eliza Doolittle as a duchess by teaching her to speak properly. He succeeds socially but fails emotionally, treating Eliza as a mere experiment rather than a human being. The play is a witty social comedy challenging class divisions and exploring questions of identity and independence.", facts: "The basis for the hit musical and film 'My Fair Lady'; Shaw won an Oscar for the 1938 film adaptation's screenplay." },
  { title: "Man and Superman", author: "George Bernard Shaw", category: "British", year: "1903", summary: "The confirmed bachelor John Tanner, a radical philosopher, is relentlessly pursued by the determined Ann Whitefield in an ironic reversal of conventional romantic pursuit. The play includes the celebrated dream sequence 'Don Juan in Hell' debating the Life Force, heaven, and human purpose. Shaw uses comedy to explore his philosophy of Creative Evolution." },
  { title: "Widowers' Houses", author: "George Bernard Shaw", category: "British", year: "1892", summary: "The well-meaning young Trench discovers that his fiancée's father Sartorius derives his income from slum properties, and that Trench's own money is indirectly invested in the same exploitation. Rather than renouncing the tainted wealth, both men accommodate themselves to the system. The play is Shaw's first, a scathing critique of middle-class complicity in social injustice." },
  { title: "Candida", author: "George Bernard Shaw", category: "British", year: "1894", summary: "The Reverend James Morell, a popular Christian Socialist clergyman, brings into his home the young poet Marchbanks, who falls in love with Morell's wife Candida. Candida is forced to choose between the two men and makes a surprising choice that subverts conventional expectations. The play is a subtle comedy exploring strength, weakness, and the nature of romantic idealism." },
  { title: "Heartbreak House", author: "George Bernard Shaw", category: "British", year: "1919", summary: "A group of English educated society gather at the eccentric Captain Shotover's house and drift through a long summer evening of aimless conversation, flirtation, and disillusionment. The evening culminates in an unexpected bombing raid. The play is Shaw's Chekhovian critique of a cultured European civilisation drifting towards catastrophe." },
  { title: "Saint Joan", author: "George Bernard Shaw", category: "British", year: "1923", summary: "The play dramatises the life of Joan of Arc from her inspired military campaigns to her trial for heresy and burning at the stake. Shaw portrays Joan as a forerunner of Protestantism and nationalism who is destroyed by the institutional forces she threatens. An epilogue imagines Joan's rehabilitation and asks whether the world is yet ready to receive its saints." },
  { title: "Mrs Warren's Profession", author: "George Bernard Shaw", category: "British", year: "1893", summary: "The educated and independent Vivie Warren discovers that her mother has funded her upbringing through running a chain of Continental brothels. Mrs Warren defends her choice as the only rational response to the economic conditions facing working-class women. The play was banned for years and is Shaw's most direct attack on capitalist exploitation and moral hypocrisy." },
  { title: "Major Barbara", author: "George Bernard Shaw", category: "British", year: "1905", summary: "Barbara Undershaft is a devoted Salvation Army major whose faith in charity is shattered when her estranged munitions magnate father Andrew Undershaft demonstrates that poverty, not sin, is the true enemy of mankind. Barbara is disillusioned but ultimately reborn into a more practical idealism. The play is Shaw's most provocative exploration of money, morality, and power." },
  { title: "Arms and the Man", author: "George Bernard Shaw", category: "British", year: "1894", summary: "The Swiss mercenary Captain Bluntschli hides in the bedroom of the Bulgarian Raina Petkoff, whose fiancé Sergius is celebrated as a war hero. Bluntschli's pragmatic and unheroic view of war deflates romantic illusions about military glory. The play is a comic satire on romantic idealism, military heroism, and the conventions of class." },
  { title: "The Doctor's Dilemma", author: "George Bernard Shaw", category: "British", year: "1906", summary: "The eminent doctor Sir Colenso Ridgeon must choose whether to use his limited new tuberculosis cure on a mediocre but worthy doctor or on the brilliant but unscrupulous artist Louis Dubedat. His decision is complicated by his love for Dubedat's wife Jennifer. The play is a tragi-comedy questioning medical ethics, artistic genius, and the value of human life." },

  { title: "Riders to the Sea", author: "J. M. Synge", category: "British", year: "1904", summary: "The old Aran Islands woman Maurya has lost her husband and five sons to the sea and now awaits the fate of her last son Bartley, who insists on sailing despite her desperate pleas. Bartley is drowned, and Maurya achieves a sorrowful acceptance that the sea can take no more from her. The play is a spare and powerful one-act tragedy drawn from Irish peasant life." },
  { title: "The Playboy of the Western World", author: "J. M. Synge", category: "British", year: "1907", summary: "The timid Christy Mahon arrives in a Mayo village boasting that he has killed his tyrannical father and is celebrated as a hero, particularly by the headstrong Pegeen Mike. When his apparently alive father turns up, Christy's heroic reputation collapses. The play caused riots on its first production and remains a masterpiece of Irish dramatic literature exploring myth-making, identity, and the romantic imagination." },

  { title: "The Countess Cathleen", author: "W. B. Yeats", category: "British", year: "1892", summary: "During a famine in Ireland, demons buy the souls of starving peasants, and the noble Countess Cathleen sells her own soul to the devil in order to buy them back and feed her people. She dies from the effort, but angels carry her to heaven since her intention was pure love. The play launched the Irish Literary Theatre and drew on Irish folklore to explore self-sacrifice and spiritual redemption." },

  { title: "Juno and the Paycock", author: "Sean O'Casey", category: "British", year: "1924", summary: "Set during the Irish Civil War, the play centres on the Boyle family in a Dublin tenement: the feckless 'Captain' Jack Boyle and his long-suffering wife Juno struggle with poverty while awaiting a legacy that never arrives. Their son is executed by former comrades and their daughter is left pregnant and abandoned. The play is a tragicomedy of working-class Dublin life, combining rich comedy with devastating tragedy." },
  { title: "The Plough and the Stars", author: "Sean O'Casey", category: "British", year: "1926", summary: "Set during the 1916 Easter Rising in Dublin, the play follows the residents of a tenement as the rebellion swirls around them, causing deaths, displacement, and grief. The idealism of the uprising is contrasted with the suffering and irony of ordinary civilian life. The play provoked riots at the Abbey Theatre and remains O'Casey's most controversial work." },
  { title: "The Shadow of a Gunman", author: "Sean O'Casey", category: "British", year: "1923", summary: "Set during the Anglo-Irish War of 1920, the poet Seumas Shields and his roommate Donal Davoren allow their neighbours to believe Davoren is an IRA gunman on the run. When a bomb is accidentally left in the flat, the brave Minnie Powell sacrifices herself to save them. The play exposes the gap between romantic nationalist rhetoric and the brutal reality of political violence." },
  { title: "The Silver Tassie", author: "Sean O'Casey", category: "British", year: "1928", summary: "The football hero Harry Heegan goes off to the First World War amid celebrations, only to return paralysed from the waist down. The expressionistic second act, set in the trenches, uses chant and symbol to depict the horror of war. The play was controversially rejected by W. B. Yeats and the Abbey Theatre, leading to O'Casey's permanent break with Ireland." },

  { title: "Murder in the Cathedral", author: "T. S. Eliot", category: "British", year: "1935", summary: "The play dramatises the return of Archbishop Thomas Becket to Canterbury in 1170 and his murder by four knights of King Henry II. Becket resists four spiritual temptations, including the temptation of martyrdom itself, before accepting his fate. The play is a verse drama exploring spiritual courage, political power, and sainthood." },
  { title: "The Family Reunion", author: "T. S. Eliot", category: "British", year: "1939", summary: "Harry, Lord Monchensey, returns to his ancestral home haunted by guilt over his wife's death at sea and pursued by spectral Eumenides visible only to him. His family's attempts at cheerful normality cannot contain his spiritual crisis. The play is a verse drama drawing on Greek tragedy to explore sin, guilt, and spiritual liberation." },
  { title: "The Confidential Clerk", author: "T. S. Eliot", category: "British", year: "1953", summary: "The business tycoon Sir Claude Mulhammer mistakes a young man named Colby Simpkins for his illegitimate son, leading to a series of comic misidentifications about parentage. The play is loosely modelled on Euripides' Ion and uses farcical plotting to explore questions of vocation, identity, and spiritual yearning. It is one of Eliot's lighter verse dramas." },
  { title: "The Cocktail Party", author: "T. S. Eliot", category: "British", year: "1949", summary: "A mysterious Unidentified Guest attends a London cocktail party and reveals himself as a psychiatrist who guides three people towards their different destinies: Edward and Lavinia to a reconciled marriage, and the idealistic Celia Coplestone to a life of spiritual dedication ending in martyrdom. The play is a verse drama exploring the spiritual choices that define human life.", facts: "A major commercial success on Broadway; won the Tony Award for Best Play in 1950." },
  { title: "The Elder Statesman", author: "T. S. Eliot", category: "British", year: "1958", summary: "A retired politician is confronted by figures from his past who remind him of his youthful moral failures.", facts: "Eliot's final play; dedicated to his second wife, Valerie; inspired by Sophocles' Oedipus at Colonus." },
  { title: "Venus Observed", author: "Christopher Fry", category: "British", year: "1950", summary: "An ageing Duke invites three former mistresses to watch an eclipse and asks his son to choose which one he should marry.", facts: "Written for Laurence Olivier; won the Queen's Gold Medal for Poetry." },
  { title: "A Phoenix Too Frequent", author: "Christopher Fry", category: "British", year: "1946", summary: "A Roman widow decides to die in her husband's tomb but is distracted by a handsome young soldier guarding a nearby corpse.", facts: "A witty one-act comedy that established Fry's reputation for exuberant poetic language." },
  { title: "The Dark Is Light Enough", author: "Christopher Fry", category: "British", year: "1954", summary: "Set during the Hungarian Revolution of 1848, a countess provides sanctuary to a deserter despite the danger to her family.", facts: "Written for Edith Evans; explores themes of non-violence and divine grace." },
  { title: "The Deep Blue Sea", author: "Terence Rattigan", category: "British", year: "1952", summary: "A woman leaves her respectable judge husband for a reckless former RAF pilot and struggles with her obsessive love and despair.", facts: "Considered Rattigan's masterpiece; adapted into a 2011 film starring Rachel Weisz." },
  { title: "The Winslow Boy", author: "Terence Rattigan", category: "British", year: "1946", summary: "A family fights a long legal battle to clear the name of their young son, who has been expelled from naval college for stealing a postal order.", facts: "Based on the real-life George Archer-Shee case; adapted into films in 1948 and 1999." },
  { title: "Separate Tables", author: "Terence Rattigan", category: "British", year: "1954", summary: "Two linked plays set in a Bournemouth hotel, exploring the lonely lives and secrets of its residents.", facts: "Adapted into an Academy Award-winning film in 1958 starring David Niven and Deborah Kerr." },
  { title: "The Browning Version", author: "Terence Rattigan", category: "British", year: "1948", summary: "An embittered and failing schoolmaster receives a small act of kindness from a pupil on his final day of teaching.", facts: "Widely regarded as one of the finest one-act plays in the English language; adapted into films in 1951 and 1994." },
  { title: "Flare Path", author: "Terence Rattigan", category: "British", year: "1942", summary: "Set in a hotel near an RAF base during WWII, the play follows the lives and loves of pilots and their wives during a bombing raid.", facts: "Based on Rattigan's own experiences as an air gunner; Winston Churchill reportedly wept when he saw it." },
  { title: "French Without Tears", author: "Terence Rattigan", category: "British", year: "1936", summary: "A group of young Englishmen at a crammer in France compete for the affections of a beautiful and manipulative girl.", facts: "Rattigan's first major success; ran for over 1,000 performances in the West End." },
  { title: "The Ghost Train", author: "Arnold Ridley", category: "British", year: "1923", summary: "A group of passengers stranded at a remote railway station are terrified by stories of a supernatural ghost train.", facts: "One of the most successful thrillers of the 1920s; written by the actor who played Private Godfrey in Dad's Army." },
  { title: "Journey's End", author: "R. C. Sherriff", category: "British", year: "1928", summary: "Set in a dugout in the British trenches during WWI, the play depicts the psychological strain on a group of officers awaiting a German attack.", facts: "Considered the greatest English play about the First World War; adapted into several films, most recently in 2017." },
  { title: "Home at Seven", author: "R. C. Sherriff", category: "British", year: "1950", summary: "A bank clerk returns home to find he has been missing for 24 hours and has no memory of what happened, fearing he may have committed a crime.", facts: "A successful post-war thriller; adapted into a 1952 film directed by and starring Ralph Richardson." },
  { title: "The White Steed", author: "Paul Vincent Carroll", category: "British", year: "1939", summary: "A clash between a rigid, puritanical priest and a more humane, liberal priest in a small Irish town.", facts: "Won the New York Drama Critics' Circle Award for Best Foreign Play." },
  { title: "Shadow and Substance", author: "Paul Vincent Carroll", category: "British", year: "1937", summary: "A scholarly, aristocratic canon and his simple, saintly servant girl are caught in the religious and social conflicts of rural Ireland.", facts: "Carroll's most famous play; won the Casement Award and the New York Drama Critics' Circle Award." },
  { title: "The Righteous Are Bold", author: "Gerard McLarnon", category: "British", year: "1946", summary: "A young Irish woman returns from England seemingly possessed by demons, leading to a conflict between science and religion.", facts: "A major success for the Abbey Theatre in Dublin." },
  { title: "The Quare Fellow", author: "Brendan Behan", category: "British", year: "1954", summary: "Set in a Dublin prison on the eve of an execution, the play explores the reactions of prisoners and warders to the death penalty.", facts: "Established Behan's international reputation; premiered at the Pike Theatre in Dublin." },
  { title: "The Hostage", author: "Brendan Behan", category: "British", year: "1958", summary: "A young British soldier is held hostage by the IRA in a Dublin brothel, surrounded by a cast of eccentric and comic characters.", facts: "Originally written in Irish as An Giall; adapted into English by Behan and Joan Littlewood's Theatre Workshop." },
  { title: "Borstal Boy", author: "Brendan Behan", category: "British", year: "1967", summary: "Adapted from Behan's memoir, it follows his experiences as a teenage IRA member in a British juvenile prison.", facts: "The stage adaptation won the Tony Award for Best Play in 1970." },
  { title: "The Shaughraun", author: "Dion Boucicault", category: "British", year: "1874", summary: "A charming Irish rogue helps a young gentleman escape the law and win back his estate and his beloved.", facts: "One of the most popular Irish melodramas of the 19th century; noted for its spectacular stage effects." },
  { title: "London Assurance", author: "Dion Boucicault", category: "British", year: "1841", summary: "A vain old baronet and his son compete for the hand of a wealthy young heiress in a series of comic misunderstandings.", facts: "Boucicault's first major success; still frequently revived by the Royal Shakespeare Company and the National Theatre." },
  { title: "The Colleen Bawn", author: "Dion Boucicault", category: "British", year: "1860", summary: "A young nobleman secretly marries a simple Irish girl but is pressured by his family to marry an heiress, leading to a murder plot.", facts: "Based on a real-life murder case; inspired the opera The Lily of Killarney." },
  { title: "The Octoroon", author: "Dion Boucicault", category: "British", year: "1859", summary: "Set on a Louisiana plantation, the play explores the tragic fate of a young woman of mixed race who is sold into slavery.", facts: "A major success in both New York and London; sparked debate over its treatment of slavery." },
  { title: "The Bells", author: "Leopold Lewis", category: "British", year: "1871", summary: "A respected burgomaster is haunted by the memory of a murder he committed fifteen years earlier.", facts: "The play that made Henry Irving a star; he performed it over 800 times during his career." },
  { title: "Caste", author: "T. W. Robertson", category: "British", year: "1867", summary: "A young nobleman marries a ballet dancer from a poor family, challenging the rigid social barriers of Victorian England.", facts: "A landmark in the development of realistic 'cup and saucer' drama." },
  { title: "The Silver King", author: "Henry Arthur Jones", category: "British", year: "1882", summary: "A man wrongly believes he has committed a murder and flees to America, where he makes a fortune before returning to clear his name.", facts: "One of the most successful melodramas of the Victorian era; praised by Matthew Arnold for its literary quality." },
  { title: "Michael and His Lost Angel", author: "Henry Arthur Jones", category: "British", year: "1896", summary: "A strict, ascetic clergyman falls into a passionate affair with a worldly woman and must face public confession and disgrace.", facts: "Considered Jones's most serious and ambitious play; caused a scandal on its publication." },
  { title: "The Liars", author: "Henry Arthur Jones", category: "British", year: "1897", summary: "A witty comedy of manners exploring the social consequences of a minor indiscretion in high society.", facts: "One of Jones's most successful comedies; noted for its sharp dialogue and social satire." },
  { title: "Mrs. Dane's Defence", author: "Henry Arthur Jones", category: "British", year: "1900", summary: "A woman's past is ruthlessly exposed during a cross-examination by a judge who suspects she is not who she claims to be.", facts: "Famous for its intense third-act cross-examination scene." },
  { title: "The Second Mrs. Tanqueray", author: "Arthur Wing Pinero", category: "British", year: "1893", summary: "A respectable widower marries a woman with a 'past', leading to social ostracism and tragic consequences for his family.", facts: "A landmark in the development of the 'problem play' in English drama; made Mrs Patrick Campbell a star." },
  { title: "Trelawny of the 'Wells'", author: "Arthur Wing Pinero", category: "British", year: "1898", summary: "A young actress leaves her theatre company to marry into a stiff, aristocratic family but finds she cannot adapt to their rigid world.", facts: "A nostalgic tribute to the theatre of Pinero's youth; adapted into the musical Trelawny in 1972." },
  { title: "The Magistrate", author: "Arthur Wing Pinero", category: "British", year: "1885", summary: "A respectable magistrate becomes involved in a series of scandalous and comic misadventures at a late-night restaurant.", facts: "One of the most successful Victorian farces; still frequently revived." },
  { title: "The Notorious Mrs. Ebbsmith", author: "Arthur Wing Pinero", category: "British", year: "1895", summary: "A radical woman living in a 'free union' with a married politician struggles with her beliefs and the pressures of social convention.", facts: "Written for Mrs Patrick Campbell; explores themes of feminism and social reform." },
  { title: "Mid-Channel", author: "Arthur Wing Pinero", category: "British", year: "1909", summary: "A bleak study of a disintegrating marriage between a middle-aged couple who have reached the 'mid-channel' of their lives.", facts: "Considered one of Pinero's most mature and realistic social dramas." },
  { title: "The Gay Lord Quex", author: "Arthur Wing Pinero", category: "British", year: "1899", summary: "A reformed rake attempts to prove his fidelity to his fiancée while being tested by a suspicious and witty manicurist.", facts: "Famous for its tense and clever third-act confrontation." },
  { title: "The Voysey Inheritance", author: "Harley Granville-Barker", category: "British", year: "1905", summary: "A young man discovers that his father's successful legal firm has been built on a massive, multi-generational fraud.", facts: "A major work of Edwardian social realism; explores themes of business ethics and family loyalty." },
  { title: "Waste", author: "Harley Granville-Barker", category: "British", year: "1907", summary: "A brilliant politician's career is destroyed by a sexual scandal and the subsequent death of his mistress after an illegal abortion.", facts: "Banned by the Lord Chamberlain for its treatment of abortion; not performed in its original version until 1936." },
  { title: "The Madras House", author: "Harley Granville-Barker", category: "British", year: "1910", summary: "A complex and intellectual study of the changing roles of women and the commercialisation of fashion in Edwardian London.", facts: "Noted for its lack of conventional plot and its focus on ideas and social observation." },
  { title: "Justice", author: "John Galsworthy", category: "British", year: "1910", summary: "A poor clerk commits a minor forgery to help the woman he loves and is crushed by the impersonal and brutal machinery of the legal and prison system.", facts: "Winston Churchill was so moved by the play that he initiated significant reforms to the British prison system." },
  { title: "The Silver Box", author: "John Galsworthy", category: "British", year: "1906", summary: "A wealthy young man and a poor man both commit a theft, but the legal system treats them very differently based on their social class.", facts: "Galsworthy's first play; established his reputation as a writer of socially conscious drama." },
  { title: "Strife", author: "John Galsworthy", category: "British", year: "1909", summary: "A long and bitter strike at a tinplate works is led by two stubborn men — the company chairman and the union leader — with tragic results for both sides.", facts: "A powerful study of industrial conflict and the human cost of uncompromising idealism." },
  { title: "Loyalties", author: "John Galsworthy", category: "British", year: "1922", summary: "A theft at a country house party exposes the conflicting loyalties of class, race, and profession among the guests.", facts: "One of Galsworthy's most successful later plays; explores themes of anti-Semitism and social prejudice." },
  { title: "The Skin Game", author: "John Galsworthy", category: "British", year: "1920", summary: "A bitter feud between an old aristocratic family and a newly wealthy industrialist leads to social warfare and personal tragedy.", facts: "Adapted into a 1931 film directed by Alfred Hitchcock." },
  { title: "The Circle", author: "W. Somerset Maugham", category: "British", year: "1921", summary: "A young woman considers leaving her husband for a lover, while her mother-in-law, who did the same thirty years earlier, returns to show the reality of such a choice.", facts: "Considered Maugham's finest comedy; a cynical and witty study of love and social convention." },
  { title: "Our Betters", author: "W. Somerset Maugham", category: "British", year: "1917", summary: "A savage satire on wealthy American women who marry into the British aristocracy for titles and the resulting social corruption.", facts: "Caused a scandal on its publication for its frank treatment of social and sexual morality." },
  { title: "The Constant Wife", author: "W. Somerset Maugham", category: "British", year: "1926", summary: "A clever woman discovers her husband is having an affair and decides to achieve financial independence and take a lover of her own.", facts: "A witty and proto-feminist comedy of manners; still frequently revived." },
  { title: "For Services Rendered", author: "W. Somerset Maugham", category: "British", year: "1932", summary: "A bleak study of the devastating long-term effects of the First World War on a single English family.", facts: "One of Maugham's most serious and controversial plays; its anti-war message was unpopular on its first production." },
  { title: "Sheppey", author: "W. Somerset Maugham", category: "British", year: "1933", summary: "A hairdresser wins a fortune and decides to live according to the literal teachings of Jesus, leading his family to believe he is insane.", facts: "Maugham's final play; an ironic and cynical look at the impossibility of true Christian charity in the modern world." },
  { title: "The Sacred Flame", author: "W. Somerset Maugham", category: "British", year: "1928", summary: "A mother kills her terminally ill and suffering son to prevent him from discovering his wife's infidelity.", facts: "A controversial 'problem play' exploring themes of euthanasia and maternal love." },
  { title: "East is West", author: "Samuel Shipman", category: "British", year: "1918", summary: "A young Chinese woman is rescued from a 'love market' and brought to America, where she struggles to adapt to Western culture.", facts: "A major commercial success in its time; reflects the 'Yellow Peril' anxieties of the early 20th century." },
  { title: "Private Lives", author: "Noël Coward", category: "British", year: "1930", summary: "A divorced couple, Elyot and Amanda, find themselves in adjacent suites at a hotel while honeymooning with their new spouses. They realize they still love each other and flee to Paris, leading to a series of witty and volatile confrontations.", facts: "Coward wrote the play in only four days while recovering from influenza in Shanghai." },
  { title: "Blithe Spirit", author: "Noël Coward", category: "British", year: "1941", summary: "The socialite Charles Condomine invites a medium, Madame Arcati, to his house for a séance as research for his new book. The séance accidentally summons the ghost of his first wife, Elvira, who proceeds to haunt him and his second wife, Ruth.", facts: "The play set a record for the longest-running non-musical play in the West End at the time." },
  { title: "Betrayal", author: "Harold Pinter", category: "British", year: "1978", summary: "The play charts a seven-year extramarital affair between Emma and Jerry, the best friend of her husband Robert. Uniquely, the story is told in reverse chronological order, revealing the layers of deception and the shifting loyalties of the three characters.", facts: "Inspired by Pinter's own seven-year affair with television presenter Joan Bakewell." },
  { title: "The Room", author: "Harold Pinter", category: "British", year: "1957", summary: "An elderly woman, Rose, lives in a single room with her silent husband Bert. Her sense of security is threatened by a series of visitors, including a mysterious blind black man who brings a message from her father.", facts: "Pinter's first play, written in four days; it established many of the themes and techniques of his later work." },

  { title: "Waiting for Godot", author: "Samuel Beckett", category: "British", year: "1953", summary: "Two tramps, Vladimir and Estragon, wait endlessly by a bare tree for a mysterious figure named Godot who never arrives. Each act repeats the same pattern, broken only by the arrival of the brutal Pozzo and his slave Lucky. The play is the defining work of the Theatre of the Absurd, exploring the human capacity to endure without meaning or hope.", facts: "Originally written in French as 'En attendant Godot'; famously described by critic Vivian Mercier as a play in which 'nothing happens, twice'." },
  { title: "Endgame", author: "Samuel Beckett", category: "British", year: "1957", summary: "In a bare room at the end of the world, the blind and domineering Hamm and his servant Clov enact their daily rituals while Hamm's legless parents Nagg and Nell sit in dustbins. Nothing changes and nothing ends; the game simply continues. The play is a bleak masterpiece of Absurdist theatre exploring dependency, entropy, and the impossibility of escape." },
  { title: "Krapp's Last Tape", author: "Samuel Beckett", category: "British", year: "1958", summary: "The elderly and decrepit Krapp listens to a tape he recorded thirty years earlier, in which his younger self dismissed a moment of human love in favour of a solitary artistic vision. He records a new tape that reflects on loss and failure. The one-act play is a haunting meditation on memory, time, and the cost of artistic ambition." },
  { title: "Breath", author: "Samuel Beckett", category: "British", year: "1969", summary: "Lasting approximately thirty-five seconds, the play consists of a stage littered with rubbish, a recorded breath of air, and a single cry, without any characters or dialogue. It encapsulates Beckett's minimalist vision of birth, existence, and death. It is one of the shortest plays ever written for the professional stage." },
  { title: "Happy Days", author: "Samuel Beckett", category: "British", year: "1961", summary: "Winnie is buried to her waist in a mound of scorched earth in the first act and to her neck in the second, yet continues her cheerful monologue of memories and routines while her husband Willie barely communicates. The play is a dark comedy about the human compulsion to maintain optimism and habit in the face of inexorable decline." },

  { title: "The Caretaker", author: "Harold Pinter", category: "British", year: "1960", summary: "The brain-damaged Aston offers shelter to the derelict tramp Davies, and a three-way power struggle develops with Aston's more aggressive brother Mick, who owns the dilapidated house. Davies attempts to play the brothers off against each other but is ultimately expelled. The play is a major work of the Theatre of Menace, exploring identity, possession, and the failure of human communication." },
  { title: "The Homecoming", author: "Harold Pinter", category: "British", year: "1965", summary: "Teddy returns to his brutal North London family home with his wife Ruth, and the male members of his family — his father Max, uncle Sam, and brothers Lenny and Joey — gradually appropriate Ruth for themselves. Ruth chooses to stay as the family's sexual servant and financial provider. The play is a disturbing and ambiguous examination of power, desire, and the dissolution of domestic values." },
  { title: "The Birthday Party", author: "Harold Pinter", category: "British", year: "1958", summary: "Stanley, a lodger in a rundown seaside boarding house, is visited by two sinister strangers, Goldberg and McCann, who subject him to a terrifying interrogation at his birthday party and eventually take him away, transformed into a blank and submissive figure. The nature of their authority and Stanley's guilt is never explained. The play established Pinter's distinctive menacing ambiguity." },
  { title: "No Man's Land", author: "Harold Pinter", category: "British", year: "1975", summary: "The wealthy but isolated literary man Hirst invites the down-at-heel poet Spooner home for drinks, and a battle of wits and identities develops through the long night. Two sinister manservants guard the household. The play is a dense and poetic meditation on memory, creativity, failure, and the fear of death." },
  { title: "The Dumb Waiter", author: "Harold Pinter", category: "British", year: "1957", summary: "Two professional hitmen, Ben and Gus, wait in a basement room for instructions about their next assignment, receiving baffling food orders through a dumb waiter. Their conversation circles uneasily around trivial details and growing anxiety. The play is a taut Absurdist thriller in which the ordinary is rendered menacing and the true nature of their assignment is gradually and shockingly revealed." },

  { title: "Look Back in Anger", author: "John Osborne", category: "British", year: "1956", summary: "The angry young working-class intellectual Jimmy Porter rants against the class-bound complacency of post-war England while treating his upper-class wife Alison with deliberate cruelty. The play caused a theatrical revolution by introducing a new kind of raw, contemporary working-class voice to the British stage. It defined the generation of 'Angry Young Men' and transformed modern British drama.", facts: "The Royal Court Theatre's press officer coined the term 'Angry Young Man' to describe Osborne." },
  { title: "The Entertainer", author: "John Osborne", category: "British", year: "1957", summary: "Archie Rice, a third-rate music-hall comedian performing in a dying variety theatre, serves as a metaphor for the declining state of Britain in the aftermath of Suez. His seedy personal life and fading performances are set against the family's grief when his son is killed in a military action. The play is a bitter elegy for lost empire and an exhausted national culture." },

  { title: "Loot", author: "Joe Orton", category: "British", year: "1965", summary: "Two young men hide the proceeds of a bank robbery in the coffin of one of their mothers, leading to increasingly outrageous black farce involving a corrupt detective and a murderous nurse. The play gleefully desecrates every institution it touches — the police, the church, motherhood, and the law. It is Orton's most fully achieved comedy, a savage anarchic farce." },
  { title: "Entertaining Mr Sloane", author: "Joe Orton", category: "British", year: "1964", summary: "The charming and amoral young lodger Mr Sloane moves into the home of the sexually predatory Kath and her brother Ed, both of whom are determined to possess him. When Sloane murders their elderly father, the siblings blackmail him into serving their sexual needs in rotation. The play is a darkly comic thriller about power, sexuality, and middle-class respectability." },
  { title: "What the Butler Saw", author: "Joe Orton", category: "British", year: "1969", summary: "A private psychiatric clinic descends into total chaos as the psychiatrist Dr Prentice's attempt to seduce a job applicant triggers a farcical spiral of cross-dressing, mistaken identity, and escalating authority figures. The mayhem culminates in the revelation that two of the characters are the lost children of Sir Winston Churchill. The play is a brilliantly constructed anarchic farce dismantling all authority and rational order." },

  { title: "The Real Inspector Hound", author: "Tom Stoppard", category: "British", year: "1968", summary: "Two theatre critics, Moon and Birdboot, watch a country house murder mystery and become increasingly drawn into the action until they themselves end up on stage and are killed. The play parodies both the conventions of the Agatha Christie whodunit and the pretensions of theatre criticism. It is an early and playful example of Stoppard's meta-theatrical wit." },
  { title: "Rosencrantz and Guildenstern Are Dead", author: "Tom Stoppard", category: "British", year: "1966", summary: "The play follows two minor characters from Hamlet, Rosencrantz and Guildenstern, as they drift through the edges of the play's action with no clear sense of purpose, identity, or free will. Their philosophical conversations about existence, chance, and death form the centre of the work. It is a major Absurdist drama that combines theatrical playfulness with genuine existential depth.", facts: "Stoppard's breakthrough play; it won the Tony Award for Best Play in 1968." },
  { title: "Jumpers", author: "Tom Stoppard", category: "British", year: "1972", summary: "The moral philosopher George Moore struggles to write a lecture defending the existence of God and absolute moral values while his wife Dotty, a retired singer, is implicated in the murder of one of a troupe of gymnast-philosophers. The play is an exhilarating intellectual comedy combining gymnastic spectacle with debates about logical positivism and moral relativism." },

  { title: "Saved", author: "Edward Bond", category: "British", year: "1965", summary: "Set in a bleak South London council estate, the play follows Len, who becomes entangled with a dysfunctional family. In the notorious central scene, a gang of youths stone a baby to death in its pram. The play caused enormous controversy and was prosecuted under the Theatres Act; it remains a landmark of British social drama about violence bred by poverty and emotional deprivation." },
  { title: "Bingo", author: "Edward Bond", category: "British", year: "1973", summary: "The play imagines Shakespeare's final years in Stratford, where he colluded with local landowners in enclosing common land despite knowing the suffering this caused to the poor. Wracked by guilt at his own moral compromise, Shakespeare commits suicide. The play is Bond's indictment of the artist who fails to act against social injustice." },
  { title: "Lear", author: "Edward Bond", category: "British", year: "1971", summary: "Bond's radical rewriting of Shakespeare's King Lear presents the ageing king as initially a tyrant building a wall to protect his kingdom, who is later deposed by his daughters and comes to understand the suffering caused by violence and power. Unlike Shakespeare's Lear, Bond's protagonist achieves political understanding through suffering. The play is a Marxist critique of cyclical political violence." },

  { title: "Top Girls", author: "Caryl Churchill", category: "British", year: "1982", summary: "The play opens with a surreal dinner party hosted by the career woman Marlene, attended by historical and fictional women from across the centuries who discuss their experiences of ambition, suffering, and gender. The second part reveals the human cost of Marlene's individualistic success through her relationship with her working-class sister Joyce and her daughter Angie. The play is a feminist examination of women's achievement and the price paid for operating within a patriarchal value system.", facts: "The play's first act features overlapping dialogue, a technique Churchill became famous for." },
  { title: "Cloud Nine", author: "Caryl Churchill", category: "British", year: "1979", summary: "The first act is set in Victorian colonial Africa, where the characters' gender, race, and sexuality are comically and deliberately miscast to expose the repressions of empire and patriarchy. The second act jumps to London in 1979, with the same characters only twenty-five years older. The play is a landmark work exploring colonialism, sexual liberation, and the evolving politics of gender." },

  // ─── AMERICAN PLAYS ───────────────────────────────────────────────────────────

  { title: "Emperor Jones", author: "Eugene O'Neill", category: "American", year: "1920", summary: "A Black American convict who has made himself emperor of a Caribbean island flees through the jungle as a native revolt closes in, haunted by visions of his past crimes.", facts: "A landmark in American theatre for its use of expressionist technique and its Black protagonist; won O'Neill early critical recognition." },
  { title: "Desire Under the Elms", author: "Eugene O'Neill", category: "American", year: "1924", summary: "On a bleak New England farm, the young wife of an old farmer falls into a passionate affair with his son, ending in infanticide and destruction.", facts: "One of O'Neill's greatest tragedies; banned in several cities on its first tour for its frank treatment of lust and murder." },
  { title: "Hairy Ape", author: "Eugene O'Neill", category: "American", year: "1922", summary: "A brutish but proud stoker on an ocean liner is humiliated by a rich passenger's daughter and spends the rest of the play desperately searching for a place where he belongs.", facts: "A key work of American expressionist theatre; the central character Yank became an iconic figure of alienated modern labour." },
  { title: "Mourning Becomes Electra", author: "Eugene O'Neill", category: "American", year: "1931", summary: "A three-part retelling of the Greek Oresteia set in New England after the Civil War, in which a mother poisons her husband and her children take revenge.", facts: "O'Neill's most ambitious work, running over five hours; contributed to his winning the Nobel Prize in Literature in 1936." },
  { title: "Long Day's Journey into Night", author: "Eugene O'Neill", category: "American", year: "1956", summary: "The Tyrone family spend a single day in their Connecticut summer home as the father's miserliness, the mother's drug addiction, and the sons' failures come painfully to the surface.", facts: "Written autobiographically about O'Neill's own family; won the Pulitzer Prize in 1957 and is widely considered the greatest American play ever written." },
  { title: "The Iceman Cometh", author: "Eugene O'Neill", category: "American", year: "1946", summary: "The regulars of a seedy New York bar cling to their pipe dreams until the arrival of a travelling salesman who claims to have found peace by abandoning all illusion.", facts: "O'Neill's penultimate masterpiece; the title is an ironic allusion to the biblical parable of the bridegroom; runs nearly five hours in performance." },
  { title: "Strange Interlude", author: "Eugene O'Neill", category: "American", year: "1928", summary: "A woman's inner psychological life across nine acts and twenty-five years is revealed through an innovative technique of spoken thoughts delivered directly to the audience.", facts: "Won the Pulitzer Prize in 1928; its use of spoken asides to reveal inner thought was a bold theatrical experiment that influenced later playwrights." },
  { title: "Cat on a Hot Tin Roof", author: "Tennessee Williams", category: "American", year: "1955", summary: "On a Southern plantation, the alcoholic Brick refuses to sleep with his wife Maggie while the family gathers around the dying patriarch Big Daddy, circling the truth about Brick's sexuality.", facts: "Won the Pulitzer Prize in 1955; adapted into a celebrated 1958 film starring Paul Newman and Elizabeth Taylor." },
  { title: "A Streetcar Named Desire", author: "Tennessee Williams", category: "American", year: "1947", summary: "The faded Southern belle Blanche DuBois moves in with her sister Stella and brutish brother-in-law Stanley Kowalski in New Orleans, and their clash ends in tragedy.", facts: "Won the Pulitzer Prize in 1948; adapted into a landmark 1951 film by Elia Kazan, which launched Marlon Brando to stardom." },
  { title: "The Glass Menagerie", author: "Tennessee Williams", category: "American", year: "1944", summary: "A frustrated young writer in St Louis is trapped between his domineering mother and his painfully shy sister Laura, who retreats into a world of glass animal figurines.", facts: "Williams's breakthrough play; semi-autobiographical; considered a cornerstone of American theatre and widely produced worldwide." },
  { title: "All My Sons", author: "Arthur Miller", category: "American", year: "1947", summary: "A successful manufacturer's past crime — shipping defective aircraft parts during World War II — slowly surfaces and destroys his family.", facts: "Miller's first major success; won the New York Drama Critics' Circle Award; adapted into a 1948 film starring Edward G. Robinson." },
  { title: "Death of a Salesman", author: "Arthur Miller", category: "American", year: "1949", summary: "The ageing salesman Willy Loman, losing his grip on reality and his job, confronts the gap between his American Dream and his actual failure as a father and man.", facts: "Won the Pulitzer Prize in 1949 and the Tony Award for Best Play; widely considered the greatest American tragedy; adapted into films in 1951 and 1985." },
  { title: "The Crucible", author: "Arthur Miller", category: "American", year: "1953", summary: "The Salem witch trials of 1692 are dramatised as a young woman's false accusations destroy an entire community, with the honest John Proctor refusing to confess to save himself.", facts: "Written as an allegory of McCarthyism; adapted into a 1996 film written by Miller himself; one of the most produced plays in American schools and theatres." },
  { title: "The Zoo Story", author: "Edward Albee", category: "American", year: "1959", summary: "On a Central Park bench, a middle-class man is confronted by an aggressive, alienated stranger named Jerry who forces an encounter that ends in violence.", facts: "Albee's debut play; first performed in Berlin before its American premiere; a key work of the American Theatre of the Absurd." },
  { title: "An American Dream", author: "Edward Albee", category: "American", year: "1961", summary: "A couple who call each other Mommy and Daddy receive a visit from Mrs Barker and a handsome Young Man, in a savage satirical attack on American middle-class values and conformity.", facts: "An early example of Albee's absurdist style; the play draws on the influence of Ionesco and Beckett to satirise the emptiness of the American Dream." },
  { title: "Who's Afraid of Virginia Woolf?", author: "Edward Albee", category: "American", year: "1962", summary: "A bitter and boozy night unfolds as a history professor and his sharp-tongued wife tear each other apart in front of a young couple they have invited home.", facts: "Won the Tony Award for Best Play in 1963; adapted into a celebrated 1966 film directed by Mike Nichols, with Elizabeth Taylor and Richard Burton." },
  { title: "A Raisin in the Sun", author: "Lorraine Hansberry", category: "American", year: "1959", summary: "The Younger family, living in a cramped apartment on Chicago's South Side, awaits a $10,000 insurance check. Each family member has a different dream for the money, leading to conflict and a confrontation with the racial prejudices of the time.", facts: "The first play written by a Black woman to be produced on Broadway." },
  { title: "Fences", author: "August Wilson", category: "American", year: "1985", summary: "Troy Maxson, a former baseball player in the Negro Leagues now working as a garbage collector, struggles with his sense of failure and his relationship with his son Cory, who wants to play college football.", facts: "Won the Pulitzer Prize for Drama and the Tony Award for Best Play." },
  { title: "The Piano Lesson", author: "August Wilson", category: "American", year: "1987", summary: "A brother and sister in 1930s Pittsburgh argue over whether to sell a family heirloom — a piano carved with images of their enslaved ancestors — to buy the land their family once worked as slaves.", facts: "Part of Wilson's 'Pittsburgh Cycle'; won the Pulitzer Prize for Drama." },
  { title: "Glengarry Glen Ross", author: "David Mamet", category: "American", year: "1983", summary: "Four desperate real estate salesmen in Chicago compete in a high-stakes sales contest, using unethical and illegal tactics to close deals and save their jobs.", facts: "Known for its fast-paced, profanity-laden dialogue; won the Pulitzer Prize for Drama." },
  { title: "Oleanna", author: "David Mamet", category: "American", year: "1992", summary: "A power struggle between a university professor and a female student who accuses him of sexual harassment after a meeting in his office.", facts: "A highly controversial play that explores themes of power, communication, and political correctness." },
  { title: "Buried Child", author: "Sam Shepard", category: "American", year: "1978", summary: "A young man returns to his family's dilapidated farmhouse in Illinois to find his relatives living in a state of decay and harboring a dark, long-buried secret.", facts: "Won the Pulitzer Prize for Drama; established Shepard as a major voice in American theatre." },
  { title: "True West", author: "Sam Shepard", category: "American", year: "1980", summary: "Two estranged brothers — a successful screenwriter and a drifter — clash while house-sitting for their mother in the California desert, eventually swapping roles.", facts: "Considered one of Shepard's finest works; explores themes of identity, family, and the myth of the American West." },
  { title: "Angels in America", author: "Tony Kushner", category: "American", year: "1991", summary: "A two-part epic set in the mid-1980s, interweaving the stories of several characters in New York City as they grapple with the AIDS crisis, politics, and spiritual visions.", facts: "A landmark of modern theatre; won multiple Tony Awards and the Pulitzer Prize for Drama." },
  { title: "Topdog/Underdog", author: "Suzan-Lori Parks", category: "American", year: "2001", summary: "Two Black brothers, Lincoln and Booth, struggle to survive in a cramped apartment, haunted by their past and their namesakes as they play three-card monte.", facts: "Parks was the first Black woman to win the Pulitzer Prize for Drama." },
  { title: "Our Town", author: "Thornton Wilder", category: "American", year: "1938", summary: "The story of the small town of Grover's Corners, New Hampshire, told through the everyday lives of its citizens, focusing on the relationship between George Gibbs and Emily Webb.", facts: "Famous for its minimal staging and its use of a Stage Manager character who speaks directly to the audience." },
  { title: "The Skin of Our Teeth", author: "Thornton Wilder", category: "American", year: "1942", summary: "The Antrobus family survives a series of world-ending catastrophes — an ice age, a flood, and a war — in a surreal and allegorical exploration of human resilience.", facts: "Won the Pulitzer Prize for Drama; noted for its unconventional structure and breaking of the fourth wall." },
  { title: "The Little Foxes", author: "Lillian Hellman", category: "American", year: "1939", summary: "The greedy and manipulative Hubbard family in the American South scheme against each other to gain control of a family business.", facts: "A sharp critique of capitalism and greed; adapted into a 1941 film starring Bette Davis." },
  { title: "The Children's Hour", author: "Lillian Hellman", category: "American", year: "1934", summary: "Two women who run a girls' boarding school have their lives destroyed when a malicious student accuses them of having a lesbian relationship.", facts: "Banned in several cities on its first production due to its subject matter; adapted into films in 1936 and 1961." },

  // ─── INDIAN PLAYS ────────────────────────────────────────────────────────────

  { title: "Abhijnanasakuntalam", author: "Kalidasa", category: "Indian", year: "c. 4th–5th century CE", summary: "King Dushyanta falls in love with the forest maiden Shakuntala, but a sage's curse makes him forget her; she is later recognised by her ring and reunited with him.", facts: "Considered the greatest work of Sanskrit literature and one of the world's greatest plays; Goethe famously praised it with the lines that inspired his Faust prologue." },
  { title: "Malavikagnimitram", author: "Kalidasa", category: "Indian", year: "c. 4th–5th century CE", summary: "King Agnimitra falls in love with the maidservant Malavika, who turns out to be a princess, and comic intrigues at court surround their union.", facts: "Considered Kalidasa's earliest surviving play; a light romantic comedy that already shows his mastery of lyrical Sanskrit verse." },
  { title: "Svapnavasavadatta", author: "Bhasa", category: "Indian", year: "c. 3rd–4th century CE", summary: "King Udayana, believing his wife Vasavadatta dead, is unknowingly served by her in disguise as he takes a second wife for political reasons.", facts: "Considered Bhasa's finest play; it is one of thirteen Sanskrit plays attributed to him discovered in 1912 in Kerala." },
  { title: "Mrichchhakatika (The Little Clay Cart)", author: "Sudraka", category: "Indian", year: "c. 4th century CE", summary: "A poor Brahmin called Charudatta falls in love with the courtesan Vasantasena, and their story unfolds amid political intrigue, comic subplots, and a near-execution.", facts: "One of the most performed Sanskrit plays in the modern era; remarkable for its sympathetic portrayal of characters from every social class." },
  { title: "Uttararamacharita", author: "Bhavabhuti", category: "Indian", year: "c. 8th century CE", summary: "The play depicts the latter part of the Ramayana — Rama's banishment of the pregnant Sita and their eventual reunion — focusing on sorrow and pathos.", facts: "Bhavabhuti's most admired work; he is considered the greatest Sanskrit playwright after Kalidasa; the play is celebrated for its emotional depth." },
  { title: "Mudrarakshasa", author: "Vishakhadatta", category: "Indian", year: "c. 4th–9th century CE", summary: "The Mauryan minister Chanakya outmanoeuvres the brilliant loyalist Rakshasa through elaborate political intrigue to secure the throne for Chandragupta Maurya.", facts: "A unique Sanskrit play with no romantic subplot; it is essentially a political thriller based on the rise of the Maurya empire." },
  { title: "The Post Office", author: "Rabindranath Tagore", category: "Indian", year: "1912", summary: "A sick child confined to his room dreams of the outside world while messengers and townspeople pass by, and the play ends with his quiet death as a kind of liberation.", facts: "Performed in London in 1913, the same year Tagore won the Nobel Prize in Literature; W. B. Yeats directed a production of it and called it a masterpiece." },
  { title: "Chitra", author: "Rabindranath Tagore", category: "Indian", year: "1892", summary: "The princess Chitra, plain of face and raised as a warrior, asks the gods for beauty to win Arjuna's love, but eventually reveals her true self to him.", facts: "Tagore's earliest play to gain international recognition; a lyrical retelling from the Mahabharata exploring inner versus outer beauty." },
  { title: "The Dumb Dancer", author: "Asif Currimbhoy", category: "Indian", year: "1957", summary: "A classical Indian dancer becomes a symbol of artistic freedom and cultural identity in a play that explores the tension between tradition and modernity.", facts: "Currimbhoy was one of India's first prominent playwrights in English; he wrote over 30 plays exploring Indian social and political themes." },
  { title: "Tughlaq", author: "Girish Karnad", category: "Indian", year: "1964", summary: "The idealistic but increasingly tyrannical 14th-century Sultan Muhammad bin Tughluq moves his capital from Delhi to Daulatabad in a megalomaniacal project that ends in disaster.", facts: "Widely seen as an allegory of post-independence Indian politics under Nehru; considered Karnad's finest play and a landmark of Indian drama in Kannada." },
  { title: "Hayavadana", author: "Girish Karnad", category: "Indian", year: "1971", summary: "A man born with a horse's head seeks to become fully human while two friends' lives are entangled in a tale of bodily transposition and incomplete identity.", facts: "Inspired by Thomas Mann's The Transposed Heads and Indian folk theatre; a key work of modern Indian drama using traditional Yakshagana storytelling conventions." },
  { title: "Nagamandala", author: "Girish Karnad", category: "Indian", year: "1988", summary: "A young woman trapped in a neglectful marriage is secretly visited at night by a cobra in human form, and the resulting pregnancy forces a comic and tense trial.", facts: "One of Karnad's most celebrated plays; draws on oral folk tales from Karnataka and explores themes of female desire and social judgement." },
  { title: "The Fire and the Rain", author: "Girish Karnad", category: "Indian", year: "1994", summary: "Based on a story from the Mahabharata, the play depicts the rivalry between two brothers — one devoted to sacrifice, the other to drama — and the gods' capricious intervention.", facts: "Karnad was awarded the Jnanpith Award in 1998, India's highest literary honour, largely for his body of dramatic work." },
  { title: "Ghashiram Kotwal", author: "Vijay Tendulkar", category: "Indian", year: "1972", summary: "A poor Brahmin rises to become the ruthless police chief of Pune under the patronage of the corrupt Nana Phadnavis, in 18th-century Maharashtra.", facts: "One of the most controversial plays in Indian theatre; its staging was disrupted by political protests in Maharashtra; a landmark of political Indian drama." },
  { title: "Sakharam Binder", author: "Vijay Tendulkar", category: "Indian", year: "1972", summary: "A crude bookbinder takes in abandoned women as domestic partners, exploiting them while loudly proclaiming his own honesty, until violence erupts.", facts: "Banned briefly by the Maharashtra government for obscenity; considered one of Tendulkar's most powerful studies of male violence and hypocrisy." },
  { title: "Kamala", author: "Vijay Tendulkar", category: "Indian", year: "1981", summary: "A journalist buys a woman from a village flesh market as a scoop for his paper, exposing the trade in human beings, but the play turns its gaze on his own exploitation of Kamala.", facts: "One of the first Indian plays to dramatise the trafficking of women; Tendulkar uses the journalist's callousness to indict the media as complicit." },
  { title: "Silence! The Court is in Session", author: "Vijay Tendulkar", category: "Indian", year: "1967", summary: "A travelling theatre troupe stages a mock trial for fun, but it turns into a real and devastating assault on an unmarried woman teacher who once had a secret affair.", facts: "Tendulkar's most widely produced play internationally; a fierce critique of middle-class Indian hypocrisy about women and sexuality." },
  { title: "Vultures", author: "Vijay Tendulkar", category: "Indian", year: "1961", summary: "A family of siblings fights like vultures over the imminent death of their father, exposing greed, lust, and moral corruption within a seemingly respectable household.", facts: "Considered Tendulkar's darkest play; the title is both literal and metaphorical as the family circles the dying man's property." },
  { title: "Friends Story", author: "Vijay Tendulkar", category: "Indian", year: "1981", summary: "The play explores the breakdown of a long friendship between two men as their lives, choices, and betrayals accumulate over many years.", facts: "One of Tendulkar's quieter, more personal works compared to his politically explosive dramas; focuses on the private cost of compromise." },
  { title: "Evam Indrajit", author: "Badal Sircar", category: "Indian", year: "1963", summary: "The Writer character attempts to give life and purpose to four ordinary characters — Amal, Vimal, Kamal, and Indrajit — but only Indrajit dares to question the meaninglessness of routine existence.", facts: "Considered Sircar's masterpiece and a landmark of Indian absurdist theatre; influenced by Beckett and Ionesco but rooted in the Bengali middle-class experience." },
  { title: "Pagla Ghoda", author: "Badal Sircar", category: "Indian", year: "1967", summary: "Four men visit the grave of a woman who died by suicide, and in a series of interwoven memories and fantasies, the stories of their relationships with her emerge.", facts: "One of Sircar's most poetically structured plays; later adapted into a Hindi film; Sircar was a pioneer of the Third Theatre movement in India." },
  { title: "Final Solutions", author: "Mahesh Dattani", category: "Indian", year: "1993", summary: "A Hindu family hides Muslim men in their home during communal riots, and the play weaves between the present and the past to expose deep-rooted prejudice on all sides.", facts: "Won the Sahitya Akademi Award in 1998; Dattani was the first playwright writing in English to win the award; one of the most important plays about Hindu-Muslim relations." },
  { title: "Tara", author: "Mahesh Dattani", category: "Indian", year: "1990", summary: "Conjoined twins are surgically separated but the parents' bias favours the boy, with devastating consequences for both children that ripple into adulthood.", facts: "One of Dattani's most celebrated plays; uses the physical separation of twins as a metaphor for gender discrimination in Indian families." },
  { title: "Dance Like a Man", author: "Mahesh Dattani", category: "Indian", year: "1989", summary: "A male Bharatanatyam dancer struggles against a society that sees classical dance as unmasculine, while his wife pays the price for his single-minded artistic ambition.", facts: "One of the most widely produced Indian plays in English; adapted into a 2004 film directed by Mahesh Manjrekar." },
  { title: "Bravely Fought the Queen", author: "Mahesh Dattani", category: "Indian", year: "1991", summary: "Two sisters married into the same wealthy family endure domestic abuse and suppressed sexuality in a Bangalore household, and the play brings their hidden lives violently to the surface.", facts: "A groundbreaking work for its frank treatment of domestic violence, female sexuality, and homosexuality in an Indian urban family." },
  { title: "On a Muggy Night in Mumbai", author: "Mahesh Dattani", category: "Indian", year: "1998", summary: "A gay man brings his male partner to meet his family in Mumbai, and the evening exposes the family's buried secrets and hypocrisies about sexuality and gender.", facts: "One of the first Indian plays to deal openly with gay relationships on stage; Dattani is the most prominent Indian playwright writing in English today." },
  { title: "Seven Steps Around the Fire", author: "Mahesh Dattani", category: "Indian", year: "1998", summary: "A sociology student investigates the murder of a hijra who was about to marry a police officer's son, uncovering a world of prejudice, desire, and institutional violence.", facts: "Originally written as a radio play for BBC Radio; Dattani's compassionate treatment of the hijra community was groundbreaking in Indian theatre." },
  { title: "Harvest", author: "Manjula Padmanabhan", category: "Indian", year: "1997", summary: "A poor Indian family sells the body organs of their son to a rich Western buyer in exchange for food and virtual reality entertainment, in a dystopian satire of globalisation.", facts: "Won the Onassis Prize for Theatre in 1997, chosen from over 1,400 entries worldwide; Padmanabhan's most celebrated work." },
  { title: "Lights Out", author: "Manjula Padmanabhan", category: "Indian", year: "1984", summary: "A middle-class family in a Delhi apartment hears a woman being attacked in the street below and debates whether to intervene, in a play about collective moral cowardice.", facts: "One of Padmanabhan's earliest plays; a chilling study of bystander apathy rooted in the realities of urban India." },
  { title: "The Other Side", author: "Manjula Padmanabhan", category: "Indian", year: "2006", summary: "A woman on one side of a wall communicates with a man on the other side in a post-apocalyptic world where the two sides represent radically different societies.", facts: "Part of Padmanabhan's ongoing interest in gender dystopia; the play extends themes from her novel Escape about the elimination of women." },
  { title: "Larins Sahib", author: "Gurucharan Das", category: "Indian", year: "1970", summary: "The play dramatises the brief and disastrous tenure of Sir Henry Lawrence as British administrator in Punjab, exploring the tragedy of an idealist destroyed by the system he serves.", facts: "One of the most historically grounded of Indian English plays; Das is better known as a novelist and journalist but this play brought him early literary recognition." },
  { title: "Ashadh Ka Ek Din", author: "Mohan Rakesh", category: "Indian", year: "1958", summary: "The poet Kalidasa leaves his beloved Mallika in their mountain village to seek fame at the royal court, and when he returns years later, she has married another man.", facts: "The first major modern play in Hindi; considered the foundational text of modern Hindi theatre; Mohan Rakesh is regarded as the father of the modern Hindi play." },
  { title: "Andha Yug", author: "Dharamvir Bharati", category: "Indian", year: "1954", summary: "Set on the last day of the Mahabharata war, the play shows a blind king, broken heroes, and a dying world as five survivors search for meaning in total destruction.", facts: "A verse play considered the greatest modern Hindi drama; Ebrahim Alkazi's landmark productions at the National School of Drama defined Indian theatre for a generation." },
  { title: "Mangalam", author: "Polly Sengupta", category: "Indian", year: "1993", summary: "A play exploring the lives and aspirations of women in a Bengali household, weaving together domestic ritual and quiet resistance across generations.", facts: "Sengupta is one of the notable women playwrights working in the tradition of modern Bengali theatre." },
  { title: "Inner Spaces", author: "Polly Sengupta", category: "Indian", year: "1998", summary: "The play explores the interior lives and emotional conflicts of women navigating the boundaries between private desire and social expectation.", facts: "Part of Sengupta's body of work examining gender and identity in contemporary Indian society through an intimate dramatic lens." },

  // ─── OTHER / WORLD PLAYS ─────────────────────────────────────────────────────

  { title: "Oedipus Rex", author: "Sophocles", category: "World", year: "c. 429 BCE", summary: "The King of Thebes investigates the murder of his predecessor and discovers, to his horror, that he himself killed his father and married his mother.", facts: "Aristotle called it the perfect tragedy in his Poetics; Freud named the Oedipus complex after it; one of the most frequently performed Greek tragedies in the world." },
  { title: "Antigone", author: "Sophocles", category: "World", year: "c. 441 BCE", summary: "After her brother is killed in battle, Antigone defies the decree of King Creon and buries him, choosing divine law over human law, and is condemned to death.", facts: "One of the most politically resonant plays ever written; staged during almost every major political repression of the 20th century, from Nazi Germany to apartheid South Africa." },
  { title: "Medea", author: "Euripides", category: "World", year: "431 BCE", summary: "The sorceress Medea, abandoned by Jason for a royal marriage, takes revenge by killing the new bride and then murdering her own children.", facts: "The most shocking of the surviving Greek tragedies; Euripides was reportedly booed at the premiere; has been adapted into opera, film, and modern plays worldwide." },
  { title: "Lysistrata", author: "Aristophanes", category: "World", year: "411 BCE", summary: "The Athenian woman Lysistrata convinces the women of Greece to withhold sex from their husbands until the men end the Peloponnesian War.", facts: "A celebrated anti-war comedy; its premise has inspired productions and adaptations in every century since; still performed worldwide for its comic and political force." },
  { title: "The Frogs", author: "Aristophanes", category: "World", year: "405 BCE", summary: "The god Dionysus descends to the underworld to bring back a great tragedian, and a contest between Aeschylus and Euripides determines who returns.", facts: "Won first prize at the Lenaia festival in Athens; remarkable for its literary criticism presented through comic debate between two dead dramatists." },
  { title: "The Clouds", author: "Aristophanes", category: "World", year: "423 BCE", summary: "A debt-ridden Athenian farmer sends his son to learn the art of clever argument from Socrates, with disastrously funny consequences.", facts: "A satirical attack on Socrates and the Sophists; Socrates reportedly stood up in the audience to show he was not offended; Plato later blamed the play for contributing to Socrates' trial." },
  { title: "Agamemnon", author: "Aeschylus", category: "World", year: "458 BCE", summary: "The Greek king Agamemnon returns home victorious from Troy only to be murdered in his bath by his wife Clytemnestra and her lover.", facts: "The first play of the Oresteia trilogy, the only complete Greek tragic trilogy to survive; considered the greatest achievement of ancient Greek drama." },
  { title: "Prometheus Bound", author: "Aeschylus", category: "World", year: "c. 430 BCE", summary: "The Titan Prometheus, chained to a rock for giving fire to humanity, debates his fate with gods and mortals while refusing to submit to Zeus's authority.", facts: "Attributed to Aeschylus, though some scholars dispute this; a foundational text of Western literature on the theme of rebellion against unjust authority." },
  { title: "The Misanthrope", author: "Molière", category: "World", year: "1666", summary: "The honest and inflexible Alceste despises the flattery and hypocrisy of Parisian society but is in love with the very witty and flirtatious Célimène who embodies everything he hates.", facts: "Considered Molière's greatest comedy and one of the supreme achievements of French classical theatre; influenced Wycherley's The Plain Dealer directly." },
  { title: "Phaedra", author: "Jean Racine", category: "World", year: "1677", summary: "Phaedra, wife of Theseus, confesses her passionate and shameful love for her stepson Hippolytus, triggering a catastrophe that destroys them both.", facts: "Considered Racine's masterpiece and the pinnacle of French neoclassical tragedy; Sarah Bernhardt's performance in the title role was legendary." },
  { title: "Huis Clos (No Exit)", author: "Jean-Paul Sartre", category: "World", year: "1944", summary: "Three dead people are locked together in a drawing room that serves as their hell, and slowly realise they are each other's torturers for eternity.", facts: "Contains the famous line 'Hell is other people'; premiered in Paris during the Nazi occupation; one of the defining works of existentialist theatre." },
  { title: "Faust", author: "Johann Wolfgang von Goethe", category: "World", year: "1808", summary: "The scholar Faust, despairing of all knowledge, makes a wager with the devil Mephistopheles to experience everything life offers, leading to seduction, tragedy, and eventual redemption.", facts: "Considered the greatest work of German literature; Part I published 1808, Part II posthumously in 1832; the Faustian bargain has become a universal metaphor." },
  { title: "Mother Courage and Her Children", author: "Bertolt Brecht", category: "World", year: "1939", summary: "A canteen woman follows the Thirty Years' War across Europe, profiting from the conflict while losing all three of her children to it.", facts: "Brecht's most celebrated play; the premiere starred his wife Helene Weigel; a founding text of epic theatre and anti-war drama worldwide." },
  { title: "The Caucasian Chalk Circle", author: "Bertolt Brecht", category: "World", year: "1944", summary: "A servant girl rescues an abandoned noble child during a revolution and raises him as her own; a judge later tests true motherhood using an ancient chalk circle test.", facts: "One of Brecht's most accessible plays; based on a Chinese legend and Klabund's earlier adaptation; a key text of Brechtian epic theatre technique." },
  { title: "Life of Galileo", author: "Bertolt Brecht", category: "World", year: "1943", summary: "The astronomer Galileo is forced by the Inquisition to recant his theory that the Earth moves around the Sun, and Brecht explores whether his recantation was cowardice or wisdom.", facts: "Brecht revised the play three times, most significantly after the atomic bombing of Hiroshima changed his view of the scientist's moral responsibility." },
  { title: "A Doll's House", author: "Henrik Ibsen", category: "World", year: "1879", summary: "Nora Helmer discovers that her husband Torvald sees her not as a wife but as a doll to be managed, and she walks out of the marriage to find herself.", facts: "One of the most influential plays in theatre history; its ending caused scandal across Europe; widely considered the first great feminist play in Western drama." },
  { title: "Ghosts", author: "Henrik Ibsen", category: "World", year: "1882", summary: "Mrs Alving has devoted her life to maintaining the reputation of her dead and debauched husband, but the past — his illegitimate son and his son's inherited syphilis — returns to destroy everything.", facts: "So scandalous on publication that no theatre would stage it for two years; attacked across Europe as immoral; now considered one of Ibsen's greatest achievements." },
  { title: "The Cherry Orchard", author: "Anton Chekhov", category: "World", year: "1904", summary: "An aristocratic Russian family returns to their beloved estate only to lose it to a peasant-born merchant at auction, unable to act in time to save the cherry orchard.", facts: "Chekhov's final play, completed just before his death; premiered at the Moscow Art Theatre directed by Stanislavski; considered the masterpiece of modern tragicomedy." },
  { title: "Three Sisters", author: "Anton Chekhov", category: "World", year: "1900", summary: "Three educated sisters and their brother dream of escaping their dull provincial town to Moscow, but inertia, romantic failure, and circumstance keep them trapped forever.", facts: "First performed by the Moscow Art Theatre; Chekhov insisted it was a comedy, while Stanislavski staged it as a tragedy; a defining work of modern theatre." },
  { title: "Six Characters in Search of an Author", author: "Luigi Pirandello", category: "World", year: "1921", summary: "Six unfinished fictional characters interrupt a theatre rehearsal and demand that the director stage their unwritten story, blurring the boundary between reality and fiction.", facts: "Caused riots on its first night in Rome; now considered the founding work of metatheatre and a forerunner of postmodern drama; Pirandello won the Nobel Prize in Literature in 1934." },
  { title: "Miss Julie", author: "August Strindberg", category: "World", year: "1888", summary: "On Midsummer's Eve, the daughter of a count engages in a dangerous and sexually charged power struggle with her father's valet, Jean.", facts: "A landmark of naturalistic theatre; explores themes of class, gender, and Darwinian struggle." },
  { title: "The Father", author: "August Strindberg", category: "World", year: "1887", summary: "A captain and his wife engage in a psychological battle for control over their daughter's education, leading to the captain's mental breakdown.", facts: "A powerful example of Strindberg's 'battle of the sexes' dramas." },
  { title: "Blood Wedding", author: "Federico García Lorca", category: "World", year: "1932", summary: "A young bride flees her wedding with her former lover, leading to a violent confrontation between the two families in the forest.", facts: "Part of Lorca's 'Rural Trilogy'; noted for its poetic language and use of surrealist elements." },
  { title: "The House of Bernarda Alba", author: "Federico García Lorca", category: "World", year: "1936", summary: "After the death of her second husband, the domineering Bernarda Alba imposes an eight-year period of mourning on her five daughters, leading to sexual tension and tragedy.", facts: "Lorca's final play, completed shortly before his execution during the Spanish Civil War." },
  { title: "Yerma", author: "Federico García Lorca", category: "World", year: "1934", summary: "A woman in rural Spain becomes obsessed with her inability to conceive a child, leading to a tragic confrontation with her husband.", facts: "Explores themes of social expectation, fertility, and the repression of women." },
  { title: "The Maids", author: "Jean Genet", category: "World", year: "1947", summary: "Two sisters who work as maids for a wealthy woman engage in elaborate role-playing games in which they take turns acting as their mistress and plotting to kill her.", facts: "Loosely based on the real-life Papin sisters murder case." },
  { title: "The Balcony", author: "Jean Genet", category: "World", year: "1956", summary: "Set in a high-class brothel during a revolution, the play follows various characters who act out their fantasies of power and authority.", facts: "A complex exploration of illusion, reality, and the nature of power." },
  { title: "The Bald Soprano", author: "Eugène Ionesco", category: "World", year: "1950", summary: "Two couples engage in a series of absurd and nonsensical conversations in a middle-class English living room.", facts: "The first play of the Theatre of the Absurd; has been performed continuously at the Théâtre de la Huchette in Paris since 1957." },
  { title: "Rhinoceros", author: "Eugène Ionesco", category: "World", year: "1959", summary: "The inhabitants of a small French town gradually transform into rhinoceroses, leaving only one man, Berenger, to resist the epidemic of conformity.", facts: "A powerful allegory of the rise of totalitarianism and the dangers of mass psychology." },
  { title: "The Chairs", author: "Eugène Ionesco", category: "World", year: "1952", summary: "An elderly couple prepares a room for a series of invisible guests, arranging chairs and delivering a message to a world that no longer exists.", facts: "A tragic farce exploring themes of isolation, failure, and the emptiness of language." },
  { title: "Ubu Roi", author: "Alfred Jarry", category: "World", year: "1896", summary: "The grotesque and cowardly Pa Ubu murders the King of Poland and seizes the throne, leading to a series of absurd and violent misadventures.", facts: "A precursor to Surrealism and the Theatre of the Absurd; its opening word caused a riot at its premiere." },
  { title: "Cyrano de Bergerac", author: "Edmond Rostand", category: "World", year: "1897", summary: "The brilliant poet and swordsman Cyrano, cursed with a large nose, helps the handsome but dim-witted Christian woo the woman they both love, Roxane.", facts: "A masterpiece of French romantic drama; has been adapted into numerous films and plays." },
  { title: "The Visit", author: "Friedrich Dürrenmatt", category: "World", year: "1956", summary: "A wealthy woman returns to her impoverished hometown and offers a massive sum of money to the citizens if they will kill the man who betrayed her years earlier.", facts: "A dark and cynical exploration of greed, justice, and the corruptibility of human nature." },
  { title: "The Physicists", author: "Friedrich Dürrenmatt", category: "World", year: "1962", summary: "Three physicists in a mental asylum — one claiming to be Newton, another Einstein, and the third visited by King Solomon — are revealed to be hiding dangerous secrets.", facts: "A satirical comedy exploring the moral responsibility of scientists in the nuclear age." },
  { title: "The Seagull", author: "Anton Chekhov", category: "World", year: "1896", summary: "A young writer and an aspiring actress struggle with their artistic ambitions and unrequited love in the Russian countryside.", facts: "The play's initial failure led Chekhov to vow never to write for the theatre again, but its subsequent success at the Moscow Art Theatre saved his career." },
  { title: "Uncle Vanya", author: "Anton Chekhov", category: "World", year: "1898", summary: "The lives of an elderly professor and his young wife are disrupted when they visit their rural estate, exposing the frustrations and wasted lives of the residents.", facts: "A masterpiece of subtext and emotional realism; explores themes of regret, unrequited love, and the search for meaning." },
  { title: "The Wild Duck", author: "Henrik Ibsen", category: "World", year: "1884", summary: "An idealistic young man attempts to reveal the truth about a family's past, leading to tragic consequences for an innocent child.", facts: "Considered one of Ibsen's most complex and ambiguous plays; explores the 'life-lie' and the danger of uncompromising idealism." },
  { title: "Hedda Gabler", author: "Henrik Ibsen", category: "World", year: "1890", summary: "The bored and manipulative Hedda Gabler, trapped in a loveless marriage, attempts to control the lives of those around her with devastating results.", facts: "The role of Hedda is considered one of the greatest challenges for an actress, often called the 'female Hamlet'." },
  { title: "Peer Gynt", author: "Henrik Ibsen", category: "World", year: "1867", summary: "A sprawling and surreal verse drama following the adventures of the boastful and imaginative Peer Gynt as he travels the world in search of himself.", facts: "Based on Norwegian folklore; famously features incidental music by Edvard Grieg, including 'In the Hall of the Mountain King'." },
  { title: "An Enemy of the People", author: "Henrik Ibsen", category: "World", year: "1882", summary: "A doctor discovers that the local spa's water is contaminated, but the town's leaders and citizens turn against him to protect their economic interests.", facts: "A powerful exploration of the conflict between individual truth and the 'compact majority'." },
  { title: "The Master Builder", author: "Henrik Ibsen", category: "World", year: "1902", summary: "An ageing architect, Halvard Solness, is haunted by his past and his fear of the younger generation until a mysterious young woman arrives to challenge him.", facts: "One of Ibsen's most symbolic and psychological later plays." },
  { title: "The Servant of Two Masters", author: "Carlo Goldoni", category: "World", year: "1746", summary: "The hungry and resourceful servant Truffaldino attempts to serve two masters simultaneously without either finding out, leading to a series of comic complications.", facts: "A classic of Commedia dell'arte; still frequently performed for its brilliant physical comedy." },
  { title: "The Mistress of the Inn", author: "Carlo Goldoni", category: "World", year: "1753", summary: "The witty and independent innkeeper Mirandolina outsmarts a series of aristocratic suitors who attempt to win her hand.", facts: "A landmark of Italian comedy; celebrated for its strong female protagonist and its critique of aristocratic pretension." },
  { title: "Death and the King's Horseman", author: "Wole Soyinka", category: "World", year: "1975", summary: "The ritual suicide of a Yoruba king's horseman, required by tradition to accompany his master in death, is interrupted by a British colonial officer, with devastating consequences.", facts: "Soyinka's most celebrated play; he won the Nobel Prize in Literature in 1986 as the first African writer to do so; based on a real event in 1946 Oyo, Nigeria." },
  { title: "The Lion and the Jewel", author: "Wole Soyinka", category: "World", year: "1959", summary: "The village beauty Sidi is pursued by both the progressive young schoolteacher Lakunle and the old but wily chief Baroka, and the play pits modernity against tradition with comic irony.", facts: "Soyinka's debut play, written while he was a student at Leeds; one of the most widely produced African plays in the world; a lively comedy about culture and desire." },
  { title: "A Dance of the Forests", author: "Wole Soyinka", category: "World", year: "1960", summary: "A complex and allegorical play written for Nigerian independence, in which the living and the dead gather for a forest festival that exposes the dark side of history.", facts: "One of Soyinka's most ambitious and difficult works; a profound meditation on the burdens of the past and the challenges of the future." },
  { title: "The Road", author: "Wole Soyinka", category: "World", year: "1965", summary: "A group of truck drivers and outcasts in a Nigerian motor park search for the 'Word' and the meaning of death in a world ruled by the god Ogun.", facts: "A dense and poetic exploration of Yoruba mythology, mortality, and the search for spiritual truth." },
  { title: "The Blood Knot", author: "Athol Fugard", category: "World", year: "1961", summary: "Two brothers in apartheid South Africa — one light-skinned and one dark-skinned — struggle with their identity and their relationship in a cramped shack.", facts: "Fugard's first major success; a powerful indictment of the racial divisions of apartheid." },
  { title: "Master Harold... and the Boys", author: "Athol Fugard", category: "World", year: "1982", summary: "A white teenager's relationship with two Black servants is poisoned by the systemic racism of apartheid South Africa during a single rainy afternoon.", facts: "Semi-autobiographical; banned in South Africa on its publication; won the Drama Desk Award for Outstanding Play." },
  { title: "Sizwe Bansi is Dead", author: "Athol Fugard, John Kani, Winston Ntshona", category: "World", year: "1972", summary: "A Black man in apartheid South Africa assumes the identity of a dead man in order to obtain a work permit and survive in a hostile system.", facts: "A landmark of collaborative 'workshop' theatre; won Tony Awards for both Kani and Ntshona." },
  { title: "The Island", author: "Athol Fugard, John Kani, Winston Ntshona", category: "World", year: "1973", summary: "Two political prisoners on Robben Island rehearse a production of Antigone as a form of resistance against their captors.", facts: "A powerful testament to the human spirit under oppression; inspired by real experiences in South African prisons." },
  { title: "Woza Albert!", author: "Percy Mtwa, Mbongeni Ngema, Barney Simon", category: "World", year: "1981", summary: "A satirical and energetic play imagining the second coming of Jesus Christ to apartheid South Africa.", facts: "A major success of the Market Theatre in Johannesburg; used physical theatre and satire to critique the absurdity of apartheid." },
  { title: "Anowa", author: "Ama Ata Aidoo", category: "World", year: "1970", summary: "A young woman in 19th-century Ghana defies her parents to marry the man she loves, only to find herself trapped in a marriage built on greed and the slave trade.", facts: "Based on a Ghanaian legend; a powerful feminist and post-colonial critique of tradition and exploitation." },
  { title: "The Dilemma of a Ghost", author: "Ama Ata Aidoo", category: "World", year: "1965", summary: "A young Ghanaian man returns from America with an African-American wife, leading to a clash of cultures and expectations within his traditional family.", facts: "Aidoo's first play; explores the 'double consciousness' of the African diaspora and the challenges of cultural reconciliation." },
  { title: "The Marriage of Anansewa", author: "Efua Sutherland", category: "World", year: "1975", summary: "The trickster figure Ananse attempts to marry off his daughter Anansewa to four different wealthy chiefs simultaneously in order to gain their riches.", facts: "A classic of modern Ghanaian drama; uses traditional 'Anansesem' storytelling techniques to create a vibrant musical comedy." },
  { title: "Edufa", author: "Efua Sutherland", category: "World", year: "1967", summary: "A wealthy and successful man, Edufa, attempts to escape a fatal curse by tricking his wife into dying in his place.", facts: "Loosely based on Euripides' Alcestis; a tragic exploration of greed, superstition, and the betrayal of love." },

];





